export const chunk1: Poem[] = [
  { id: 101, title: "感遇·兰若生春夏",
    author: "陈子昂",
    dynasty: "唐",
    category: "唐",
    summary: "兰若生春夏，芊蔚何青青，幽独空林色，朱蕤冒紫茎",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "感遇·兰若生春夏", original: "兰若生春夏，芊蔚何青青，幽独空林色，朱蕤冒紫茎，迟迟白日晚，袅袅秋风生，岁华尽摇落，芳意竟何成", translation: `兰草和杜若生长在春夏时节，多么茂盛又多么青翠啊！它们有幽雅孤独的风姿，胜过空旷的山林景色。红色的花苞从紫色的茎上探出头来。太阳慢慢地落下去，白昼越来越短；秋风轻轻地吹起来了。美好的花草最终都凋零飘落了，它们的芳香和心意到底能成就什么呢？`, interpretation: `这首诗写于陈子昂被贬官之后，他心中很委屈，想回家却回不了。诗人用兰花和杜若这些香草来比喻自己——长得好看又有才华，却没人欣赏。夏天它们开得热闹，到了秋天也只能随风飘落。这就像有本事的人遇不到好时候，再有香气也白搭。陈子昂开创了唐代感怀诗的新写法，这种'借花草说心里话'的方式，后来很多人都在用，比如李白、杜甫都受到他的影响。` }] },
  { id: 102, title: "早梅",
    author: "柳宗元",
    dynasty: "唐",
    category: "唐",
    summary: "早梅发高树，迥映楚天碧，朔风飘夜香，繁霜滋晓白",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "早梅", original: "早梅发高树，迥映楚天碧，朔风飘夜香，繁霜滋晓白，欲为万里赠，杳杳山水隔，寒英坐销落，何用慰远客", translation: `高高的树上梅花早早地开放了，远远望去，映照着南方湛蓝的天空。北风夜里吹来，飘散着梅花的清香；浓霜覆盖花朵，让它显得更加洁白。我真想把梅花折下来寄给远方的亲人，可是山高水远路不通，寒梅就这样凋零了，拿什么来安慰远方的游子呢？`, interpretation: `这首诗写于柳宗元被贬永州时期。诗人远离家乡，心中愁苦，看见早梅开放，既惊喜又伤感。诗中最妙的是"朔风飘夜香"和"繁霜滋晓白"——北风中暗香浮动，浓霜里洁白愈显，把早梅傲寒而开的品格写得生动极了。柳宗元借梅花寄托思念，也借它表达自己虽处困境依然清高不屈的心。后来"繁霜滋晓白"常被用来形容品格的高洁。` }] },
  { id: 103, title: "渔翁",
    author: "柳宗元",
    dynasty: "唐",
    category: "唐",
    summary: "渔翁夜傍西岩宿，晓汲清湘燃楚竹，烟销日出不见人，欸乃一声山水绿",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "渔翁", original: "渔翁夜傍西岩宿，晓汲清湘燃楚竹，烟销日出不见人，欸乃一声山水绿，回看天际下中流，岩上无心云相逐", translation: `傍晚，渔翁把船停在西山脚下过夜。天亮了，他挑起清澈的湘江水，点燃楚地的竹竿烧火煮饭。等到炊烟散尽、太阳升起，四周却看不见一个人影。突然，渔舟摇橹的声音"欸乃"一声响过，山水一下子变得更加青翠。回头望去，天边的小船正顺流而下，岸上的白云正自由自在地追逐嬉戏。`, interpretation: `这是柳宗元被贬到永州时写的小诗，当时他心情郁闷，便借山水来排遣。西山、湘江、白云，都是他笔下的好朋友。诗里有个特别有趣的画面：渔翁烧完饭，人不见了，只听见一声摇橹，山水就变绿了——这可是诗人的魔法，用声音唤出颜色。苏轼最欣赏这首诗，还专门仿写了一首，可见它有多出名。读着读着，你是不是也想坐上小船，去山水间晃一晃呢？` }] },
  { id: 104, title: "金铜仙人辞汉歌（节选）",
    author: "李贺",
    dynasty: "唐",
    category: "唐",
    summary: "衰兰送客咸阳道，天若有情天亦老",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "金铜仙人辞汉歌（节选）", original: "茂陵刘郎秋风客，夜闻马嘶晓无迹，画栏桂树悬秋香，三十六宫土花碧，衰兰送客咸阳道，天若有情天亦老", translation: `汉武帝刘彻已经躺在茂陵里，成了秋风中的过客。夜里好像还能听到他的马在嘶叫，天亮一看却什么踪迹都没有。当年雕花的栏杆和桂树还飘着秋天的香气，三十六座宫殿如今都长满了碧绿的苔藓。衰败的兰花在咸阳道上送别远去的金铜仙人。如果老天爷也有感情，他也会因为伤心而衰老。`, interpretation: `这首诗写于李贺晚年。当时唐朝由盛转衰，藩镇割据、宦官专权，李贺空有才华却屡试不第、仕途无望，身心俱疲。诗中汉武帝刘彻曾求仙问道、追求长生，最终却只能孤独地葬在茂陵；巍峨的宫殿也长满青苔，繁华化为尘土。诗人借古讽今，感叹再辉煌的王朝、再伟大的人物，终敌不过时间的流逝。全诗最震撼的名句是“天若有情天亦老”，连无情的天都会因多情而衰老，足见诗人内心的悲愤与苍凉。后来宋代欧阳修、石延年等大文豪都化用过这句，成为千古名句。` }] },
  { id: 105, title: "浪淘沙·其六",
    author: "刘禹锡",
    dynasty: "唐",
    category: "唐",
    summary: "日照澄洲江雾开，淘金女伴满江隈，美人首饰侯王印，尽是沙中浪底来",
    tags: "唐,民生",
    color: "#f59e0b",
    sections:[    { id: 1, title: "浪淘沙·其六", original: "日照澄洲江雾开，淘金女伴满江隈，美人首饰侯王印，尽是沙中浪底来", translation: `同学们，我们来读一读刘禹锡的《浪淘沙·其六》。清晨的时候，太阳慢慢升起来，金色的阳光照在清澈的小洲上，江面上那层薄薄的雾气也被阳光一点点吹散了。雾气散开以后，一群结伴而来的淘金姑娘们便出现在江湾里，热热闹闹地开始了一天的工作。同学们，你们知道吗？这些姑娘辛辛苦苦从江沙浪底淘出来的金子，最后都去了哪里呢？有的被打造成了美人头上闪闪发亮的首饰，漂亮极了；有的则被铸成了侯王手里象征权力的金印，威风凛凛。这句写得好，诗人用这样鲜明的对比告诉我们一个朴素的道理：不管是多么华丽的首饰，还是多么尊贵的金印，它们的源头都是一样的，全都是普通人从江沙浪底一点一点辛苦淘出来的啊。`, interpretation: `这首诗写于唐代，诗人刘禹锡常关心百姓生活。他巧妙地把淘金女和贵族豪门放在一起对比：达官贵人们戴的金饰、用的金印，看着金光闪闪，可追根究底，全是这些普通女子在浪涛泥沙中辛辛苦苦淘出来的！诗中没有一句直接抱怨，却让读者自己感受到劳动者的辛苦与不易。'尽是沙中浪底来'一句更是点睛之笔，传诵千年，提醒人们每一份荣华背后都有默默付出的汗水。` }] },
  { id: 106, title: "悯农·其二",
    author: "李绅",
    dynasty: "唐",
    category: "唐",
    summary: "锄禾日当午，汗滴禾下土，谁知盘中餐，粒粒皆辛苦",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "悯农·其二", original: "锄禾日当午，汗滴禾下土，谁知盘中餐，粒粒皆辛苦", translation: `同学们，我们来读一读这首《悯农》。这首诗的作者李绅生活在唐朝，他看到农民种地非常辛苦，心里很同情，就写下了这首诗。我们先看第一句：“锄禾日当午”，说的是中午的时候，太阳火辣辣地照在头顶上，可农民伯伯还在田里弯着腰，拿着锄头给禾苗松土、除去杂草。接着是“汗滴禾下土”，他们的汗水一滴滴地落下来，掉在禾苗根下的泥土里，这句写得好，让我们好像真的看到了农民伯伯流汗的样子。最后两句“谁知盘中餐，粒粒皆辛苦”是在问大家：你碗里的米饭，每一粒都是农民伯伯辛苦种出来的，所以我们要珍惜粮食，不能浪费呀！`, interpretation: `这首诗写于唐朝，那时候很多农民辛苦种田却吃不饱饭。李绅看到农人顶着烈日干活，心里很心疼，于是写下了这首小诗。诗里最打动人的就是"汗滴禾下土"——你能想象吗，烈日当头，汗水一滴一滴砸进泥土里，那画面既辛苦又心酸。整首诗短短二十个字，没有用难懂的词，却让人懂得要珍惜每一粒粮食。这首诗流传了一千多年，每次我们吃饭挑食或浪费时，爸爸妈妈念起"粒粒皆辛苦"，都是在提醒我们：粮食来之不易，要感谢每一位种田人。` }] },
  { id: 107, title: "菊花",
    author: "元稹",
    dynasty: "唐",
    category: "唐",
    summary: "秋丛绕舍似陶家，遍绕篱边日渐斜，不是花中偏爱菊，此花开尽更无花",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "菊花", original: "秋丛绕舍似陶家，遍绕篱边日渐斜，不是花中偏爱菊，此花开尽更无花", translation: `同学们好，我们来读一读这首《菊花》。一丛丛金灿灿的菊花围绕着房屋盛开，就好像东晋大诗人陶渊明家种满菊花的小院一样。这句写得好，一个'绕'字让我们仿佛看见菊花挨挨挤挤、热热闹闹地围在房子四周的样子。我独自在竹篱边一边走、一边细细地欣赏菊花，看着看着，不知不觉太阳已经西斜了，我竟然忘了回家。在众多鲜花中，我并不是偏偏特别偏爱菊花呀，而是因为菊花是秋天最后开放的花，它一旦凋谢过后，整个冬天就再也找不到别的花可以欣赏了。诗人用这一句告诉我们，要珍惜秋天这最后一道美丽的风景。`, interpretation: `这是唐代诗人元稹的一首咏菊诗。诗写在深秋百花凋零之时，诗人漫步菊丛，感慨万千。诗人先以东晋大诗人陶渊明酷爱菊花来衬托自己对菊花的喜爱，再用“不是偏爱”这种“否定式”来强调——他爱的其实是菊花那最后绽放的倔强品格。这首诗最妙的是后两句：菊花是秋天最后的花朵，等它凋谢，整个世界就只剩枯枝了。这种在终点处绽放的精神，让菊花成了坚强、高洁的象征。后来人们用“此花开尽更无花”来形容那些在困境中依然坚持的人，激励了一代又一代的小读者哦！` }] },
  { id: 108, title: "感遇·其一",
    author: "张九龄",
    dynasty: "唐",
    category: "唐",
    summary: "草木有本心，何求美人折",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "感遇·其一", original: "兰叶春葳蕤，桂华秋皎洁，欣欣此生意，自尔为佳节，谁知林栖者，闻风坐相悦，草木有本心，何求美人折", translation: `同学们，我们来读一读张九龄的《感遇·其一》。春天来了，兰草的叶子长得多么茂盛葱郁；秋天到了，桂花又是那样洁白明亮。这句写得好，一个“春”字，一个“秋”字，就把兰桂各自最美的时节点出来了。兰桂顺应季节，欣欣向荣地生长，自有它们美好的节操。谁能想到，那些隐居山林的高人雅士，闻到兰桂的芬芳香气，也会满心欢喜呢？最后两句是全诗最深刻的地方：兰桂散发香气，是出于草木的天性本心，并不是为了让美人来攀折、欣赏自己啊。`, interpretation: `这首诗写于张九龄被贬为荆州长史之后，唐玄宗后期朝政昏暗，他借物抒情来表达心志。诗人以兰桂自比：兰叶春天茂盛、桂花秋月皎洁，都是顺应天性的自然之美。核心意象是"兰桂"——它们芳香高洁，不求人知，恰如诗人坚守的气节。艺术上最妙的是结尾的反问："草木有本心，何求美人折"，表面说草木，其实说的是自己——我有我的品格，何必为了求取功名富贵而委屈自己？这两句后来成为千古名句，常被用来赞美那些不慕虚荣、保持本真的人。` }] },
  { id: 109, title: "寄李儋元锡",
    author: "韦应物",
    dynasty: "唐",
    category: "唐",
    summary: "去年花里逢君别，今日花开已一年，世事茫茫难自料，春愁黯黯独成眠",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "寄李儋元锡", original: "去年花里逢君别，今日花开已一年，世事茫茫难自料，春愁黯黯独成眠", translation: `同学们，我们来读一读这首诗。诗的开头说：去年花里逢君别，意思是在去年百花盛开的时节，我和好朋友李儋在这美好的春天里相遇，却又不得不分别。一个“逢”字，一个“别”字，离别的不舍都藏在里面了。今天花开已一年，转眼间花儿又开了，日子过得真快呀，和你分别整整一年了。世事茫茫难自料，人生的事情就像眼前的一片茫茫大雾，自己都难以预料，不知道未来会发生什么。春愁黯黯独成眠，春天本该是让人高兴的季节，可我的心里却“黯黯”的，也就是闷闷不乐、提不起劲，只好独自一人闷头睡去，借睡觉来打发这难熬的愁绪。这句写得好，一个“独”字最能表达诗人孤独的心情。`, interpretation: `这是唐代诗人韦应物写给朋友李儋的一首感怀诗，大约作于他任职滁州刺史时期。诗中以"花"串联起时间——去年花下分别，今年花开已是一年，淡淡几笔道出对友人的深切思念。"春愁"二字是全诗情感的核心，春日本该欢聚，却只能独眠，愁绪更浓。这首诗语言朴素，不堆砌华丽辞藻，却字字含情，读来让人鼻酸。后来"世事茫茫难自料"一句常被人引用，来感慨人生无常、前路难测。` }] },
  { id: 110, title: "春江花月夜",
    author: "张若虚",
    dynasty: "唐",
    category: "唐",
    summary: "春江潮水连海平，海上明月共潮生，人生代代无穷已，江月年年望相似",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "春江花月夜", original: "春江潮水连海平，海上明月共潮生，人生代代无穷已，江月年年望相似", translation: `同学们，我们来读一读这四句诗。春天的江潮汹涌澎湃，潮水和大海连成一片，水天一色，分不清哪里是江、哪里是海。这时，一轮明月从海上升起，仿佛是被潮水托起来一样，跟着潮水一同涌向远方。这句写得好，一个“共”字把明月和潮水写得像一对好朋友，亲密无间。接着，诗人由眼前的景色想到了人生：人类一代接一代地繁衍生息，永远没有尽头，可江上的那一轮明月，一年又一年，似乎还是老样子，没什么变化。读到这里，你有没有觉得，时光虽然一去不复返，但月亮却冷冷地看着人间，成了最好的见证者。`, interpretation: `这是唐代大诗人张若虚《春江花月夜》中最著名的四句诗。诗写于初唐，当时人们喜欢在月光下思考人生。这几句先写景：春天的大江、大海、明月、潮水，画面壮阔又安静。接着笔锋一转，从大自然想到人生——人一代代地出生老去，可江上的月亮却年年相似，好像什么都没改变。这种“人短暂、月永恒”的对比，是全诗最动人的地方，也让这首诗成了千古名篇。` }] },
  { id: 111, title: "夜月",
    author: "刘方平",
    dynasty: "唐",
    category: "唐",
    summary: "更深月色半人家，北斗阑干南斗斜，今夜偏知春气暖，虫声新透绿窗纱",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "夜月", original: "更深月色半人家，北斗阑干南斗斜，今夜偏知春气暖，虫声新透绿窗纱", translation: `同学们，我们来读一读唐代诗人刘方平的这首《夜月》。这首诗写的是春天夜晚的景象，诗人静静地坐在屋里，感受着悄悄来临的春天。

第一句“更深月色半人家”，意思是夜已经很深了，月光只照亮了半个院落，说明此时已是半夜时分，安静极了。

第二句“北斗阑干南斗斜”，北斗星和南斗星都横斜着挂在天边。“阑干”是横斜的样子，这里写出夜深人静、星星都快要落下的景象。这句写得好，用星星的倾斜，告诉我们时间已经很晚了。

第三句“今夜偏知春气暖”，诗人今夜特别感觉到春天的温暖气息已经悄悄来到。“偏知”就是“才知道”，说明春天的到来不易察觉，要细细体会才能发现。

第四句“虫声新透绿窗纱”，小虫子的叫声第一次透过绿色的窗纱传进屋里。“新透”是“第一次透过”，一个“新”字写出诗人惊喜的心情——原来，虫声就是春天到来的信号呀！整首诗让我们明白：只要用心感受，身边处处都有春的气息。`, interpretation: `这首诗写于唐代，描绘了一个初春夜晚的独特感受。诗中抓住了两个小巧的意象：半照人家的月光和报春的小虫。前两句写静谧的夜色，北斗南斗横斜，月光只照半边，安静得仿佛能听见时间流过；后两句笔锋一转，从虫鸣里听出了春天的脚步，写得细腻又生动。整首诗最妙的就是‘新透’二字——虫声是第一次透过窗纱，一个‘新’字写出了惊喜和发现。这种从细微处发现春光的手法，对后来写春的诗影响很大，比如那句‘今夜偏知春气暖’，常被用来形容最先感知春天的人。` }] },
  { id: 112, title: "菩萨蛮",
    author: "温庭筠",
    dynasty: "唐",
    category: "唐",
    summary: "小山重叠金明灭，鬓云欲度香腮雪，懒起画蛾眉，弄妆梳洗迟",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "菩萨蛮", original: "小山重叠金明灭，鬓云欲度香腮雪，懒起画蛾眉，弄妆梳洗迟，照花前后镜，花面交相映，新帖绣罗襦，双双金鹧鸪", translation: `清晨醒来，阳光透过绣花窗帘照在脸上，闪烁不定。乌云般的鬓发快要垂落到雪白的脸颊。她懒洋洋地起来，慢慢地描画着细长的眉毛，又慢吞吞地梳洗打扮。对着前后两面镜子，头上插的鲜花映照在镜中，人面和花面相互辉映，好看极了。刚刚熨平绣花丝绸短襦上，贴绣着一双双金色的鹧鸪鸟。`, interpretation: `这首词出自晚唐，词人温庭筠被称为“花间派”词人之首。那时候许多文人喜欢写闺怨词，这首就是写一位年轻女子清晨梳妆的情景。你看，词人特别厉害，他用“小山”代指女子额前的发式，“鬓云”形容像云一样浓密的头发，“香腮雪”说脸颊白嫩又带香气，短短几句话就把一位美丽的女子写活了。最后“新帖绣罗襦，双双金鹧鸪”最有趣，衣服上绣的鹧鸪都是成双成对的，反衬出女子独自一人的孤单。温庭筠这种精巧华丽的写法，影响了后来很多词人，词这种文学体裁也因为他变得更美了。` }] },
  { id: 113, title: "无题·来是空言",
    author: "李商隐",
    dynasty: "唐",
    category: "唐",
    summary: "来是空言去绝踪，月斜楼上五更钟，梦为远别啼难唤，书被催成墨未浓",
    tags: "唐,爱情",
    color: "#f59e0b",
    sections:[    { id: 1, title: "无题·来是空言", original: "来是空言去绝踪，月斜楼上五更钟，梦为远别啼难唤，书被催成墨未浓，蜡照半笼金翡翠，麝熏微度绣芙蓉，刘郎已恨蓬山远，更隔蓬山一万重", translation: `他说要来终究是句空话，一去便没了踪影。月光斜照小楼，天已五更，钟声悠悠入耳。梦里我为远别的人哭泣，喊也喊不醒他。匆匆写信想寄给他，墨汁还没研浓。烛光映照着半笼翠羽帐，麝香微微飘过芙蓉绣被。唉，我就像那刘郎，早已怨恨蓬山太远，可我和他之间，比蓬山还要远上一万重呢！`, interpretation: `这是李商隐写给远方恋人的一首无题诗，大约作于他中年时期仕途不顺、爱情失意之时。诗人心中思念的人许下诺言要来相会，却最终失约，连影子也见不着。诗中用月光、钟声、烛影、麝香这些精致又清冷的意象，营造出一种又美又惆怅的深夜思念氛围。尤其结尾把心上人比作蓬莱仙山之外更遥远的地方，想见却见不到，遗憾到了极点。这两句成了千古名句，后来人们形容两人相隔极远、心愿难遂时，常会借用'蓬山万重'的说法。李商隐最厉害的地方，就是把说不出口的心事，写成这么美又这么让人心疼的句子。` }] },
  { id: 114, title: "瑶瑟怨",
    author: "温庭筠",
    dynasty: "唐",
    category: "唐",
    summary: "冰簟银床梦不成，碧天如水夜云轻，雁声远过潇湘去，十二楼中月自明",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "瑶瑟怨", original: "冰簟银床梦不成，碧天如水夜云轻，雁声远过潇湘去，十二楼中月自明", translation: `同学们，我们来读一读这首诗。这首《瑶瑟怨》是唐代诗人温庭筠的作品，写的是一位女子在秋夜里孤独难眠的心情。我们先看第一句：冰簟银床梦不成。冰簟，意思是冰凉的竹席；银床，指装饰华美的床榻。她躺在清凉的竹席上、雕花的床榻中，却怎么也睡不着，连梦都做不成，可见心里有多愁闷。接着看第二句：碧天如水夜云轻。秋夜的天空蓝得像水一样澄澈透明，薄薄的云彩在天边轻轻飘过，夜色多么静谧。可正是在这样安宁的夜里，她却辗转难眠。第三句：雁声远过潇湘去。远处传来大雁的鸣叫声，它们排着队飞过了潇水和湘水，向遥远的南方飞去。雁儿秋天南飞本是寻常景象，可是孤单的人听来，反而更觉得冷清。最后一句：十二楼中月自明。十二楼，这里是指想象中极高的楼阁；月自明，意思是月亮自己静静地亮着。楼中人儿无心赏月，可月光却不理会人的愁苦，依旧独自明亮地照着。这句写得好，一个“自”字，把那份无人陪伴的孤独写得格外动人。整首诗读完我们知道：全诗没有一个愁字，却处处透着深深的愁意，写的是秋夜怀人的绵绵哀思。`, interpretation: `这首诗写于晚唐，那时国家动荡，诗人们常借写景来寄托心中的愁绪。温庭筠用'冰簟银床'写出秋夜的清冷，用'碧天如水'描绘夜空的澄澈，再用远飞的大雁和独照的明月，营造出孤寂幽远的意境。全诗没有写'愁'字，却处处透着愁思，这就是古典诗词'情景交融'的妙处。'雁声远过潇湘去'一句尤其动人，成了千古名句，让人读到就能感受到那份空旷和思念。` }] },
  { id: 115, title: "经行偶成",
    author: "李商隐",
    dynasty: "唐",
    category: "唐",
    summary: "春日在天涯，天涯日又斜，莺啼如有泪，为湿最高花",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "经行偶成", original: "春日在天涯，天涯日又斜，莺啼如有泪，为湿最高花", translation: `同学们，我们来读一读这首《经行偶成》。这是一首写景抒情的小诗，诗人在春日里独自远行，看见眼前的情景，心中涌起了淡淡的愁绪，于是写下了这四句。我们一句一句来看：第一句“春日在天涯”，意思是春天已经来到了遥远的天涯。诗人远离家乡，所以看到那熟悉的春天，反而觉得格外遥远。“天涯”两个字，突出了他人在旅途的孤单。第二句“天涯日又斜”，是说天涯的太阳又快要落山了。一天将尽，光线渐渐变暗，更让人感到时光易逝、心情低落。这句写得好，把“日斜”和“天涯”连在一起，景中带情。第三句“莺啼如有泪”，黄莺本来叫声欢快，可诗人听着，却觉得它像是在啼哭。一个“如”字，把鸟鸣写成了人哭，这是诗人的心里在难过呀！最后一句“为湿最高花”，那眼泪啊，打湿了枝头上最高的那一朵花。诗人不说自己伤心，却让黄莺替自己落泪，构思非常巧妙。读完全诗，我们能感受到诗人客居他乡、思念故国的那份深深的哀愁。`, interpretation: `这首小诗写于李商隐晚年漂泊之时，他远离家乡，独自一人。天涯，既是说自己走到了天的尽头，也暗指家乡远不可及。诗人用春日、黄莺、落日、最高处的花这些意象，描绘出一幅美丽却让人心酸的画面。黄莺本该欢唱，为何啼哭？因为它也懂得游子思乡的苦。短短二十字，没有一个愁字，却处处是愁。这种不说愁而愁意自现的手法，是李商隐最厉害的地方。` }] },
  { id: 116, title: "已凉",
    author: "韩偓",
    dynasty: "唐",
    category: "唐",
    summary: "碧阑干外绣帘垂，猩色屏风画折枝，八尺龙须方锦褥，已凉天气未寒时",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "已凉", original: "碧阑干外绣帘垂，猩色屏风画折枝，八尺龙须方锦褥，已凉天气未寒时", translation: `翠绿色的栏杆外面，绣着花纹的帘子正静静地低垂着。屏风是鲜艳的猩红色，上面画着一枝弯曲的花木，枝条舒展，栩栩如生。床榻上铺着八尺宽的龙须草席，还加盖着方形的锦缎被褥，既柔软又华丽。从这些陈设可以感受到，屋子的主人正处在天气刚刚转凉、却还未到寒冷的时候。`, interpretation: `这首诗写于晚唐时期，韩偓通过描写一个精致华美的房间，悄悄藏着一位独守空房的女子。诗人没有写人，却处处写人：碧绿的栏杆、绣花的帘子、画着折枝的屏风、铺好的锦褥……一件件摆设都像是在等人回来，可房间里却安安静静。"已凉天气未寒时"是全诗最妙的一句，"凉"的不只是天气，更是等待中慢慢变冷的心。这首诗最大的特点叫"以景写情"，不直接说想念、不直接说寂寞，却让读者自己读出淡淡的忧伤。后来"以乐景写哀情"的写法，很多诗人都受到了它的启发。` }] },
  { id: 117, title: "官仓鼠",
    author: "曹邺",
    dynasty: "唐",
    category: "唐",
    summary: "官仓老鼠大如斗，见人开仓亦不走，健儿无粮百姓饥，谁遣朝朝入君口",
    tags: "唐,讽刺",
    color: "#f59e0b",
    sections:[    { id: 1, title: "官仓鼠", original: "官仓老鼠大如斗，见人开仓亦不走，健儿无粮百姓饥，谁遣朝朝入君口", translation: `同学们，我们来读一读这首《官仓鼠》。这是唐代诗人曹邺写的一首小诗，他用短短五句话，把贪官污吏比作大老鼠，进行了一番辛辣的讽刺。下面我们一句一句地来看。第一句"官仓老鼠大如斗"，说的是官家粮仓里的老鼠，肥大得竟然像斗一样大，"斗"是古代盛粮食的器具，形容老鼠又肥又大。第二句"见人开仓亦不走"，写的是这些老鼠胆子特别大，看见有人来开仓门，也不肯逃跑，可见它们平日里多么逍遥自在。第三句"健儿无粮百姓饥"，"健儿"指的是守卫边疆的将士，这句写得好——一边是老鼠吃得肥肥胖胖，一边是保家卫国的将士和种田的老百姓却饿着肚子，形成了鲜明的对比。最后一句"谁遣朝朝入君口"，是诗人愤怒的质问：是谁天天把粮食送进你们这些老鼠嘴里呢？这首诗表面写老鼠，实际上是在痛骂那些中饱私囊的贪官，是他们把国家的粮食装进了自己的腰包。`, interpretation: `这首诗写于唐朝末年，那时候官府贪腐严重，粮食都被老鼠和贪官糟蹋了。诗人用"大如斗"的老鼠来比喻那些偷吃国家粮食的贪官污吏，特别有趣又特别犀利。"健儿无粮百姓饥"一句特别让人心酸——前线的士兵和平常百姓都在挨饿，粮食却全进了老鼠（贪官）的肚子。最后一句"谁遣朝朝入君口"是反问，其实是质问：到底是谁在养这些硕鼠？这首诗最大的特点就是"以鼠喻贪官"，用最简单的小动物说出了最深刻的道理，是中国古代讽刺诗里的经典名篇。` }] },
  { id: 118, title: "雪",
    author: "罗隐",
    dynasty: "唐",
    category: "唐",
    summary: "尽道丰年瑞，丰年事若何，长安有贫者，为瑞不宜多",
    tags: "唐,民生",
    color: "#f59e0b",
    sections:[    { id: 1, title: "雪", original: "尽道丰年瑞，丰年事若何，长安有贫者，为瑞不宜多", translation: `同学们好，我们来读一读这首《雪》。人人都说啊，这场雪是丰年的好兆头，瑞雪兆丰年嘛。可是诗人要问一问了：丰年的日子究竟过得怎样呢？这句写得好，用一个问句把读者的心提了起来。下两句是：长安城里还有挨冻受饿的穷人，所以这场瑞雪实在不该下得太多啊。诗人是在告诉大家，雪下得越大，穷苦的人就越发愁，他们没有暖和的棉衣，没有热乎的屋子，再大的雪对他们来说不是福气，而是苦难。`, interpretation: `这首诗写于晚唐，战乱频繁，百姓困苦。一般人都把大雪当成丰收的吉兆，可诗人却反其道而行之，替长安街头的贫民喊出心里话：他们饥寒交迫，再大的雪只会带来更多冻馁，哪还有心思赏雪盼丰年？全诗短短四句，用“尽道”与“为瑞不宜多”的鲜明对比，揭露了社会不公，是唐代少见的“为贫者立言”的讽喻佳作，读来让人心里一暖又一酸。` }] },
  { id: 119, title: "江村即事",
    author: "司空曙",
    dynasty: "唐",
    category: "唐",
    summary: "钓罢归来不系船，江村月落正堪眠，纵然一夜风吹去，只在芦花浅水边",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "江村即事", original: "钓罢归来不系船，江村月落正堪眠，纵然一夜风吹去，只在芦花浅水边", translation: `同学们，我们来读一读唐代诗人司空曙的《江村即事》。第一句“钓罢归来不系船”，意思是：渔翁钓完鱼，划着小船回到家中，却懒得把船拴在岸边的桩子上。第二句“江村月落正堪眠”，说的是：江边的小村庄里，一轮明月慢慢落到山后，四周安安静静，正是人们舒舒服服睡觉的好时候。第三句“纵然一夜风吹去”，意思是：哪怕夜里忽然刮来一阵大风，把小船吹走了。第四句“只在芦花浅水边”，诗人一点也不担心，因为水很浅，岸边长满了白茫茫的芦花，船就算被风推着跑，也只会搁浅在芦苇丛里。这首诗写得好在用一件生活小事，把江村夜晚那种宁静、自由又略带慵懒的氛围写了出来，读来让人心里也跟着轻松下来。`, interpretation: `这首诗是唐代诗人司空曙写的，写的是江边小村的夜晚。中晚唐时战乱频繁，很多人向往宁静的田园生活，所以这类闲适的小诗特别受欢迎。诗里最有趣的地方是“不系船”，按常理船要拴牢才安全，可诗人偏不拴，因为江村水浅芦花多，船根本跑不掉！这种“反常却合理”的写法，让小村庄的安宁、淳朴一下子跳到眼前。诗虽然短，却把乡居的自在和信任写活了，是唐诗里写田园生活的小清新代表。` }] },
  { id: 120, title: "雨晴",
    author: "王驾",
    dynasty: "唐",
    category: "唐",
    summary: "雨前初见花间蕊，雨后兼无叶里花，蛱蝶飞来过墙去，却疑春色在邻家",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "雨晴", original: "雨前初见花间蕊，雨后兼无叶里花，蛱蝶飞来过墙去，却疑春色在邻家", translation: `同学们，我们来读一读这首诗。诗人告诉我们：下雨之前，他刚刚看见花心里还藏着小小的花蕊；等一场春雨下完之后，再抬头一看，连叶子中间的花瓣也全都落光了。这句写得好！一场雨，就让花朵凋零，读起来真让人心里有些惋惜。接着，诗人说有一只蝴蝶飞过来，在院子里绕了一圈，最后竟然越过院墙，飞到了邻居家里去。诗人看着远去的蝴蝶，忽然产生了一个有趣的念头——他反倒怀疑，那美丽的春色并没有消失，只是悄悄地跑到了隔壁邻居家去藏起来了。这正是这首诗最妙的地方：明明是花已落尽，诗人却用一句“却疑春色在邻家”，把无影无踪的春光写得好像会跑会藏一样，充满了童趣和想象力。`, interpretation: `这是晚唐诗人王驾写的一首小诗，短短二十个字，把雨后春天的有趣画面写活了。这首诗写于一个普通的雨后，诗人原本想欣赏花儿，结果发现花瓣被打落，花园里空荡荡的。这时，几只蝴蝶飞过来，毫不犹豫地越过墙头，去了邻居家。诗人灵机一动，猜想着：难道是春姑娘也跟着蝴蝶跑走了吗？这种把蝴蝶当成春色信使的想法，特别有童趣。整首诗最大的特色就是结尾的奇思妙想——“却疑春色在邻家”，明明是花儿被打掉了，诗人却不直说，而是怪春色跑去了隔壁家，这样写既让人觉得好笑，又让人忍不住想：也许隔壁真的更美呢？这首诗因为最后一句流传很广，后来人们还用“春色满园关不住”形容美好的事物挡也挡不住。` }] },
  { id: 121, title: "早梅",
    author: "张谓",
    dynasty: "唐",
    category: "唐",
    summary: "一树寒梅白玉条，迥临村路傍溪桥，不知近水花先发，疑是经冬雪未销",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "早梅", original: "一树寒梅白玉条，迥临村路傍溪桥，不知近水花先发，疑是经冬雪未销", translation: `同学们好，我们来读一读唐代张谓的《早梅》吧。诗人走在乡村的小路上，远远地看见有一棵梅树，它的枝条洁白光滑，像是用白玉雕琢而成一般。这句写得好，一个“白玉条”的比喻，一下子就让梅花的高洁姿态出现在我们眼前。接着看第二句，诗人说它生长在偏僻的地方，远远地挨着乡村的小路，靠着小溪和小桥，真是又清静又幽雅。到了第三句，诗人自己也感到奇怪：为什么这棵梅树这么早就开花了呢？原来是它靠近溪水，得到了水汽的滋养，所以比别的花先一步绽放。最后一句最妙，诗人远远望去，还以为枝头那一片洁白，是去年冬天没有融化的残雪呢。这一句既写出了梅花颜色的洁白，也写出了它盛开在寒风中、让人分不清是花是雪的奇妙景象。整首诗的中心就在最后一句——它告诉我们，梅花不与百花争艳，而是在寒冷中默默开放，是多么坚强、多么特别啊！`, interpretation: `这首诗写于唐代，那时候诗人很喜欢在诗里描写梅花，把梅花当成坚强、高洁的象征。诗里最妙的是把白梅比作白雪，远远一看分不清是花还是雪，这就是诗人故意留的“小悬念”，让读诗的人也跟着好奇：到底是花还是雪呢？最后一句才悄悄揭开答案，原来开在水边的梅花早早绽放啦。这首诗把视觉上的错觉写得特别有趣，短短四句就让人记住了一树寒梅的清冷美丽，也成了写梅诗里的经典名句。` }] },
  { id: 122, title: "兰溪棹歌",
    author: "戴叔伦",
    dynasty: "唐",
    category: "唐",
    summary: "凉月如眉挂柳湾，越中山色镜中看，兰溪三日桃花雨，半夜鲤鱼来上滩",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "兰溪棹歌", original: "凉月如眉挂柳湾，越中山色镜中看，兰溪三日桃花雨，半夜鲤鱼来上滩", translation: `同学们，我们来读一读唐代诗人戴叔伦的这首《兰溪棹歌》。一弯像眉毛一样细细的凉月，悄悄挂在长满柳树的河湾上空；清澈平静的兰溪水面，像一面明亮的镜子，把越中青翠秀丽的山色完完整整地映照出来。这句写得好，一个“挂”字让弯月仿佛有了生命，静静地依偎在柳枝之间。淅淅沥沥的春雨一连下了三天，溪水渐渐涨了起来；到了半夜，肥美的鲤鱼趁着水涨，纷纷从深水里跃出，欢快地游到了浅滩之上。整首诗短短四句，却把月夜、青山、春雨、活鱼都写活了，告诉我们：只要留心观察身边的一山一水、一鱼一月，就能发现无穷的诗意。`, interpretation: `这首诗是唐代诗人戴叔伦任东阳（今浙江）县令时游兰溪所作，写的是春天夜晚兰溪的美景。诗中最妙的是"凉月如眉"和"山色镜中看"，一弯新月像弯弯的眉毛，清冷可爱；平静的溪水像一面镜子，把青山的倒影清清楚楚地映了出来。后两句写春雨后溪水上涨，鱼儿都蹦到浅滩上玩耍，画面一下子活了起来。整首诗短短四句就像一幅会动的山水画，对仗工整、动静相衬，尤其"半夜鲤鱼来上滩"一句充满童趣，让人读了就觉得春天真美好，因此千古传诵。` }] },
  { id: 123, title: "古风·其十九",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "西上莲花山，迢迢见明星，素手把芙蓉，虚步蹑太清",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "古风·其十九", original: "西上莲花山，迢迢见明星，素手把芙蓉，虚步蹑太清", translation: `诗人一路向西，去攀登那座又高又美的莲花山。他走了很远很远的路，终于抬起头，看见天上有一颗明亮的星星，那就是传说中住在华山的明星仙子。这位仙子真美呀，她伸出一双洁白如玉的手，轻轻采下一朵盛开的芙蓉花。采完花，她并没有走在实实在在的地上，而是踩着空气，仿佛踏在云端一样，在高高蓝蓝的太空中悠闲地漫步。`, interpretation: `这首诗写于安史之乱后，李白借游仙来表达对乱世的失望和对美好世界的向往。诗中主角是华山玉女明星仙子，她手捧莲花，在天空漫步，画面飘逸优美。李白用"素手""芙蓉""虚步"这些词，把神仙写得亲切又高贵，仿佛一位美丽的姐姐在云中起舞。"虚步蹑太清"是千古名句，那种轻盈飘逸的感觉让人过目难忘。后来许多诗人都模仿这种游仙写法来寄托自己的理想。` }] },
  { id: 124, title: "秋浦歌·其二",
    author: "李白",
    dynasty: "唐",
    category: "唐",
    summary: "秋浦猿夜愁，黄山堪白头，青溪非陇水，翻作断肠流",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "秋浦歌·其二", original: "秋浦猿夜愁，黄山堪白头，青溪非陇水，翻作断肠流", translation: `同学们，我们来读一读李白的《秋浦歌·其二》。诗人独自来到秋浦河边，看见猿猴在夜里一声声哀啼，仿佛在诉说自己的忧愁。他望着自己满头的白发，感慨地说：哎呀，这白发就像黄山上的白雪一样啊！这句写得好，把诗人的愁苦一下子写到了极致。接着，他看着眼前青溪的流水，想起那著名的“陇头水”，那是古人用来寄托思乡之情的流水。虽然青溪并不是陇头水，但此刻它翻涌着流过诗人眼前，竟也变得让人肝肠寸断，仿佛要把他满腹的乡愁都带走。这首诗的每一句都带着浓浓的哀伤，写尽了诗人漂泊在外的孤独与思念。`, interpretation: `这首诗写于李白晚年漫游秋浦（今安徽贵池）时。当时他年过半百，怀才不遇，远离故乡，愁绪满怀。诗中用猿猴夜啼、白发如雪、流水断肠几个意象，把思乡的苦和人生失意的痛融在一起。写法上短短二十字却层层递进，先写听到猿声，再写自己白发，最后借水抒愁，特别动人。“翻作断肠流”一句想象奇特，成为千古名句，后来许多诗人写愁思都会化用这种写法。` }] },
  { id: 125, title: "与浩初上人同看山寄京华亲故",
    author: "柳宗元",
    dynasty: "唐",
    category: "唐",
    summary: "海畔尖山似剑芒，秋来处处割愁肠，若为化得身千亿，散上峰头望故乡",
    tags: "唐,思乡",
    color: "#f59e0b",
    sections:[    { id: 1, title: "与浩初上人同看山寄京华亲故", original: "海畔尖山似剑芒，秋来处处割愁肠，若为化得身千亿，散上峰头望故乡", translation: `同学们，我们来读一读这首诗。诗人柳宗元被贬到偏远的海边，触景生情，写下这首寄给远方亲友的小诗。首句“海边尖尖的山峰像剑的锋芒”，一个比喻就把山的陡峭尖锐写了出来。“秋天一来，处处都像在割我的愁肠”，这句写得好啊，秋天本就是让人伤感的季节，再加上海风萧瑟，游子心中那浓浓的思乡之情，仿佛真的被那利刃般的山峰一道一道割开了，多么痛！于是诗人奇思妙想：如果能变化出千千万万个自己，散落到每一座山峰上，抬起头就能望一望远方的故乡，该有多好。这份深切的思念，令人动容。`, interpretation: `这首诗写于柳宗元被贬到永州的时候。诗人远离京城，一个人站在海边，看着眼前一座座又尖又利的山，心里头那种想家的愁苦，就像被刀割一样难受。诗人异想天开：要是自己能变成一千亿个人，就让每一个身影都站到不同的山顶上，一起眺望远方的家乡。这是多么浪漫又心酸的想象啊！诗中把尖山比作剑芒，是柳宗元很出名的写法，后来人们形容山势险峻，常常会说'如剑如芒'。整首诗短短四句，却藏着说不完的思念。` }] },
  { id: 126, title: "剑客",
    author: "贾岛",
    dynasty: "唐",
    category: "唐",
    summary: "十年磨一剑霜刃未曾测试君谁有不平事",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "剑客", original: "十年磨一剑霜刃未曾测试君谁有不平事", translation: `同学们，我们来读一读唐代诗人贾岛的这首小诗《剑客》。诗人用短短几句话，写出了一位身怀绝技、等待机会为民除害的侠客形象。我们一句一句来看：第一句“十年磨一剑”，说的是这位剑客花费了整整十年的光阴来磨炼一把宝剑，可见他十分用心、十分刻苦。第二句“霜刃未曾试”，意思是剑刃锋利得仿佛能划开寒霜，却还没有真正试用过它的锋芒。这句写得好，一个“未曾试”，透露出剑客在等待一个展示本领的机会。后两句“今日把示君，谁有不平事”，意思是今天我把宝剑拿出来给您看一看，请问——您有没有遇到什么不公平的事情需要我帮忙？整首诗表面是在写剑，其实是在写人，表达了剑客身怀绝技却甘愿为正义出手的豪迈气概。`, interpretation: `这首诗写于唐朝，那时候很多人怀才不遇，梦想有朝一日能被重用。诗人贾岛把自己比作一把磨了十年的宝剑，虽然锋利无比却没人发现，所以忍不住想：谁有不平事，就来找我吧！诗里最妙的就是'霜刃未曾试'五个字，把宝剑的冷峻和诗人的傲气都写出来了，读起来特别带劲儿。这首诗短短二十个字，却成了千古名句，常被人用来形容身怀绝技、等待施展的人才呢！` }] },
  { id: 127, title: "题诗后",
    author: "贾岛",
    dynasty: "唐",
    category: "唐",
    summary: "两句三年得，一吟双泪流，知音如不赏，归卧故山秋",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "题诗后", original: "两句三年得，一吟双泪流，知音如不赏，归卧故山秋", translation: `同学们好，我们来读一读贾岛的《题诗后》。这首诗讲的是诗人写诗时那种反复推敲、苦心琢磨的辛苦。"两句三年得"，是说这两句诗他整整琢磨了三年才写出来，可见用功之深。"一吟双泪流"，吟，就是诵读；诗写成之后，他忍不住一读再读，激动得两眼泪水流下来。"知音如不赏"，知音，指真正懂自己、欣赏自己的人；赏，就是欣赏。"归卧故山秋"，意思是说，假如知心朋友不欣赏这首诗，那他情愿回到故乡的山林里，在秋风中躺下来安安静静休息。这句写得好，透着一股淡淡的忧伤，也让我们懂得了好诗来之不易。`, interpretation: `这是唐代“推敲诗人”贾岛在诗成之后写下的感言。贾岛作诗极讲究字句，据说连“推”和“敲”都要反复斟酌，所以为了两句诗甘愿苦熬三年，写成后自己读着都感动落泪。诗中“知音”点出他渴望被人理解的心愿，“故山秋”则流露出淡淡的失落与归隐之意。整首诗语言朴素，却把诗人作诗的痴迷、孤独和真诚写得十分动人，也成了后世形容创作艰辛的名句。` }] },
  { id: 128, title: "再经胡城县",
    author: "杜荀鹤",
    dynasty: "唐",
    category: "唐",
    summary: "去岁曾经此县城，县民无口不冤声，今来县宰加朱绂，便是生灵血染成",
    tags: "唐,讽刺",
    color: "#f59e0b",
    sections:[    { id: 1, title: "再经胡城县", original: "去岁曾经此县城，县民无口不冤声，今来县宰加朱绂，便是生灵血染成", translation: `同学们，我们来读一读这首《再经胡城县》。诗人说，去岁的时候，我曾经路过这座县城。那时候啊，全县的老百姓没有一个人不在喊冤叫屈，声音到处都是。第二年，诗人又一次经过这里，却发现了一个让人震惊的变化：这位县官头上又添了红色的官带（朱绂，就是系在官帽上的红色丝带），官位又升了一级。这句写得好！诗人愤怒地写道：他那身显赫的官服，分明是用老百姓的鲜血染成的啊！同学们，这首诗揭露了官吏欺压百姓、用百姓的血泪换取自己升官发财的黑暗现实，表现了诗人对劳动人民的深切同情和对贪官污吏的强烈愤恨。`, interpretation: `这首诗写于唐末乱世，杜荀鹤路过胡城县，目睹官府欺压百姓的惨状。诗中最震撼的是“朱绂”与“血染”的对比——官员升官时身上耀眼的红袍，竟是百姓的血泪染成！诗人没有直接骂官，只用“便是”二字轻轻一点，却让人脊背发凉。这种不露声色的讽刺手法非常高明，诗也因此成为千古传诵的名句，提醒我们：真正的官服应该用为民办事的汗水来染，而不是百姓的血泪。` }] },
  { id: 129, title: "山中寡妇",
    author: "杜荀鹤",
    dynasty: "唐",
    category: "唐",
    summary: "夫因兵死守蓬茅，麻苎衣衫鬓发焦，桑柘废来犹纳税，田园荒后尚征苗",
    tags: "唐,民生",
    color: "#f59e0b",
    sections:[    { id: 1, title: "山中寡妇", original: "夫因兵死守蓬茅，麻苎衣衫鬓发焦，桑柘废来犹纳税，田园荒后尚征苗", translation: `同学们，我们来读一读这首诗。丈夫因为战乱死在了战场上，可怜的妻子只能独自守着山中的茅草屋艰难度日。她身上穿的，是粗麻和苎麻织成的破旧衣衫；她的两鬓头发，又枯又黄，看得出多年的辛苦与忧愁。桑树和柘树本是养蚕织丝的来源，如今却被砍伐一空，可官府依然上门来催收丝税。田园早已荒芜，连一粒粮食都种不出来，朝廷却还要继续征收田赋。这句写得好——一边是百姓已经走投无路，一边是官吏追索不止，读来让人心中发酸。诗人杜荀鹤正是借这位山中寡妇的悲惨遭遇，控诉了战乱给百姓带来的深重苦难。`, interpretation: `这首诗写于晚唐战乱时期，藩镇割据、战火连年，无数百姓家破人亡。诗人杜荀鹤擅长写民间疾苦，这首《山中寡妇》就像一幅悲惨的画卷：一个失去丈夫的女人，住在破茅屋里，穿的是粗糙麻衣，连鬓发都枯黄了——这是长期吃不饱、营养不良的样子。更可怜的是，桑树没了还要交税，田地荒了还要交租，官府根本不管老百姓的死活！诗人用朴实的语言，不加修饰，却字字扎心。这种为百姓说话的诗歌传统，影响了后来的白居易等人，也让我们今天读到时，依然能感受到那份沉甸甸的心疼。` }] },
  { id: 130, title: "富贵曲",
    author: "郑遨",
    dynasty: "唐",
    category: "唐",
    summary: "美人梳洗时，满头间珠玉，岂知两片月，戴却数乡税",
    tags: "唐,讽刺",
    color: "#f59e0b",
    sections:[    { id: 1, title: "富贵曲", original: "美人梳洗时，满头间珠玉，岂知两片月，戴却数乡税", translation: `同学们，我们来读一读这首《富贵曲》。它讲的是一位富贵人家的女子，早晨梳妆打扮的情景。"美人梳洗时，满头间珠玉"——说的是美丽的女子正在梳妆，头上满满地插着、戴满了珍珠和宝玉。"岂知两片月，戴却数乡税"中的"岂知"是"哪里知道"的意思，诗人要发问了：她头上戴的珠玉，弯弯的像两片月牙儿，可她哪里晓得，这一点点首饰的钱，竟然抵得上好几个乡下农民交的好几年赋税啊！"戴却"是"戴掉"、"花掉"的意思。这句写得好，用一个梳头的小镜头，就把富贵人家奢靡浪费、百姓生活艰辛的不公平写得清清楚楚，让人读了心里很不是滋味。`, interpretation: `这首诗写在唐末战乱频繁、官吏横行的年代，老百姓日子苦不堪言。诗人郑遨是个看透世事的人，他用"两片月"这样美丽的词来形容贵妇人头上的珠玉，可紧接着就揭开真相——这么一点点小玩意儿，能换走好几个村庄的赋税！这种把富贵人家的奢华和百姓的苦难放在一起对比的写法特别厉害，让人一下子就能感受到不公平。"岂知"两个字最戳心：富太太们美滋滋地打扮自己，根本不知道自己的快乐是建立在别人的痛苦上。这首诗就像一则短短的小故事，教会孩子们：真正的美不在于穿戴多少珠宝，而在于心里有没有装着别人。` }] },
  { id: 131, title: "金陵图",
    author: "韦庄",
    dynasty: "唐",
    category: "唐",
    summary: "谁谓伤心画不成，画人心逐世人情，君看六幅南朝事，老木寒云满故城",
    tags: "唐,怀古",
    color: "#f59e0b",
    sections:[    { id: 1, title: "金陵图", original: "谁谓伤心画不成，画人心逐世人情，君看六幅南朝事，老木寒云满故城", translation: `同学们，我们来读一读唐代诗人韦庄的《金陵图》。金陵就是今天的南京，历史上许多朝代在这里建都，留下了无数兴亡往事。这首诗是诗人看了六幅描绘南朝旧事的画之后写下的感受。

第一句"谁谓伤心画不成"，意思是谁说画不出伤心的事情呢？这是一个反问，意思是伤心的事情是画得出来的。第二句"画人心逐世人情"，逐是追随、迎合的意思，说的是画画的人只想着迎合世人喜欢热闹、喜欢吉祥的心情，所以故意画得热热闹闹，而不去表现那些让人伤感的场面。

第三、四句"君看六幅南朝事，老木寒云满故城"，君就是你，诗人请你来看看这六幅画吧，画的都是南朝的旧事，只见枯老的树木和寒冷的云雾笼罩着整座旧城。

这句写得好！不说繁华，只写老树寒云，越冷清越让人感到朝代兴亡的悲伤。诗的中心就是：真正打动人心的画，不在于华丽，而在于真实地画出历史的沧桑。`, interpretation: `这是唐代诗人韦庄看了六幅描绘南朝古都金陵（今南京）的画后写下的诗。当时唐末战乱不断，金陵屡经兴衰，诗人借画抒怀。诗中最动人的是“老木寒云满故城”——枯树与寒云布满整座古城，六个字就画出萧瑟凄凉的画面，让人仿佛能感受到历史的沧桑。整首诗以议论开头，用画面结尾，告诉我们：真正打动人的画，不在于技巧多华丽，而在于是否画出了真情实感。` }] },
  { id: 132, title: "水调歌头（节选）",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "明月几时有，把酒问青天，但愿人长久，千里共婵娟",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "水调歌头（节选）", original: "明月几时有，把酒问青天，不知天上宫阙，今夕是何年，我欲乘风归去，又恐琼楼玉宇，高处不胜寒，起舞弄清影，何似在人间，转朱阁低绮，户照无眠不，应有恨何事长，向别时圆人，有悲欢离合月，有阴晴圆缺此，事古难全但，愿人长久千，里共婵娟", translation: `明月从什么时候才开始有的呢？我端着酒杯，仰头问青天。不知道天上的神仙宫殿里，今天晚上到底是哪一年。我想乘着清风飞回月宫去，又害怕那美玉砌成的楼阁太高，使人受不住寒冷。在月下翩翩起舞，欣赏着自己的影子，哪里比得上人间美好啊！月光转过朱红的楼阁，低低地照进雕花的窗户，照着失眠的人。月亮对人该没有什么怨恨吧，为什么总是在人们离别时才圆呢？人有悲欢离合的变迁，月有阴晴圆缺的转换，这种事自古以来就难以两全。只希望我们彼此都能长长久久地活着，即使相隔千里，也能共赏这美好的明月。`, interpretation: `这首词写于北宋神宗熙宁九年的中秋之夜，当时苏轼和弟弟苏辙已经七年没有见面，他因为和朝廷意见不合被外放到密州做官，心里很不是滋味。那晚他一个人喝醉了，对着月亮写下了这首词。整首词最厉害的地方，就是把天上的月亮和地上的人心连在一起——月亮有阴晴圆缺，人有悲欢离合，谁都躲不过。但他最后却来了一句'但愿人长久，千里共婵娟'，把所有的伤感都化成了祝福：只要我们都好好活着，哪怕隔着千山万水，抬头看见的就是同一轮月亮。这句话后来成了中国人表达思念时最爱说的话，千年之后读起来，还是让人鼻子一酸。` }] },
  { id: 133, title: "念奴娇·赤壁怀古（节选）",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "大江东去，浪淘尽，千古风流人物，故垒西边，人道是，三国周郎赤壁，乱石穿空，惊涛拍岸，卷起千堆雪",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "念奴娇·赤壁怀古（节选）", original: "大江东去，浪淘尽，千古风流人物，故垒西边，人道是，三国周郎赤壁，乱石穿空，惊涛拍岸，卷起千堆雪，江山如画，一时多，少豪杰", translation: `滚滚长江向东奔流而去,浪花淘尽了千百年来那些了不起的人物。在旧时营垒的西边,人们说那就是三国时候周瑜大败曹军的赤壁。陡峭的岩石直插天空,惊人的浪涛拍打着江岸,卷起的浪花好像千万堆白雪。江山美得像画一样,那一时间,有多少英雄豪杰啊!`, interpretation: `这首词写于苏轼被贬黄州时,心情虽然有些郁闷,但他来到赤壁古战场,想象当年三国英雄,反而变得豪迈起来。词中最厉害的是'乱石穿空,惊涛拍岸,卷起千堆雪'三句,短短十几个字就把赤壁的险峻和江水的汹涌写活了,像看电影一样有画面感。'大江东去,浪淘尽,千古风流人物'更是千古名句,后来很多人写长江、写历史都会想起它,连小说《三国演义》的开篇都受到它的影响呢!` }] },
  { id: 134, title: "江城子·乙卯正月二十日夜记梦",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "十年生死两茫茫，不思量，自难忘，千里孤坟无处话，凄凉",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "江城子·乙卯正月二十日夜记梦", original: "十年生死两茫茫，不思量，自难忘，千里孤坟无处话，凄凉纵使相，逢应不识尘，满面鬓如霜，夜来幽，梦忽还，乡小轩窗正梳妆，相顾无言惟，有泪千行料得年，年肠断，处明月，夜短松冈", translation: `十年了，你走了十年，我活着十年，生死相隔，两边都迷迷糊糊。我虽然不去想你，可这份思念又怎么能忘得了？你的坟在千里之外，我连找个地方说说心里话都没有。就算我们再见面，你大概也认不出我了吧——我满脸风尘、两鬓已经白得像霜一样。今天夜里，我做了一个幽幽的梦，忽然又回到了家乡，你坐在小窗前，正在梳头打扮。我看着你，你看着我，千言万语却说不出一句，只有眼泪一行一行地流下来。想到那座长着小松树的山冈上，年年明月照着你的孤坟，我的心就要痛断了。`, interpretation: `这是苏轼四十岁那年在密州做的梦。妻子王弗去世整整十年了，他还是忍不住在梦里和她相见。词里有三个最动人的画面："千里孤坟"是距离的远，"小轩窗正梳妆"是记忆的近，"明月夜短松冈"是思念的永恒。苏轼厉害的地方在于，他写爱情，却不说"我爱你"，全用画面说话——一个梳头的背影，一行流的眼泪，就够了。"相顾无言，惟有泪千行"成了千古名句，因为每个人心里都有一段想说又说不出口的话。这首词也开创了"梦中忆亡妻"的写法，后来纳兰性德写的悼亡词，都是受它影响。` }] },
  { id: 135, title: "定风波",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "莫听穿林打叶声，何妨吟啸且徐行，竹杖，芒鞋轻胜马谁怕，一蓑烟雨任平生",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "定风波", original: "莫听穿林打叶声何妨吟啸且徐行竹杖芒鞋轻胜马谁怕一蓑烟雨任平生料峭春风吹酒醒微冷山头斜照却相迎回首向来萧瑟处归去也无风雨也无晴", translation: `不用去管那风雨穿过树林、敲打树叶的声音，只管一边慢慢走，一边随口吟诗、吹吹口哨。拄着竹杖，穿着草鞋，比骑马还要轻快舒服。有什么可怕的呢？披一件蓑衣，在烟雨中度过一生，也挺好。带着寒意的春风吹来，酒意醒了，微微有点冷。抬头一看，山头的夕阳正斜斜地照过来，像是在迎接我。回头看看刚才走过的风雨萧瑟的地方，不管是回去还是继续走，都没什么两样——没有风雨，也没有晴天。`, interpretation: `这首词写于苏轼被贬到黄州的第三年，他和朋友们出门游玩，半路上突然下起了大雨，同行的人都觉得很狼狈，只有苏轼毫不在意。雨后，他写下了这首词。最有趣的是“竹杖芒鞋轻胜马”——拄着竹杖、穿着草鞋，竟然比骑马还轻快！这是因为心里轻松自在啊。词中最出名的是最后一句：“也无风雨也无晴”，意思是无论风雨还是晴天，他都能坦然面对。这正是苏轼最了不起的地方——不管生活给他多大的打击，他都能笑呵呵地扛过去。这种乐观洒脱的心态，感动了无数后人，也让这首词成为宋词中最受欢迎的篇章之一。` }] },
  { id: 136, title: "记承天寺夜游（节选）",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "庭下如积，水空明水，中藻荇交，横盖竹柏，影也何夜，无月何处，无竹柏但，少闲人如，吾两人耳",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "记承天寺夜游（节选）", original: "元丰六年十月十二日夜解衣欲睡月色入户欣然起行庭下如积水空明水中藻荇交横盖竹柏影也何夜无月何处无竹柏但少闲人如吾两人耳", translation: `元丰六年十月十二日的夜晚，我解开衣服准备睡觉。这时，月光照进了窗户，我高兴地起身走出去。院子里的地面像积满了清澈的月光水，水中有水草交错纵横——原来是竹子和柏树的影子啊。哪一夜没有月光？哪里没有竹子和柏树？只是缺少像我俩这样清闲有趣的人罢了。`, interpretation: `这是苏轼被贬到黄州后写的小品文。1080年前后，他因“乌台诗案”被贬，心里苦闷，却学会了在平凡日子里找乐子。短短八十多字，写了一个清幽的月夜：他看见月光洒满庭院，把竹柏的影子比作水草，写得特别有想象力。最有名的是最后两句——月亮和竹柏到处都有，可不是谁都能像他俩一样，停下脚步静静欣赏。苏轼用最平常的字，说出了一个道理：再美的东西，也得有闲心才能发现。` }] },
  { id: 137, title: "和子由渑池怀旧",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "人生到处知何似，应似飞鸿踏雪泥，泥上偶然留指爪，鸿飞那复计东西",
    tags: "宋,哲理",
    color: "#06b6d4",
    sections:[    { id: 1, title: "和子由渑池怀旧", original: "人生到处知何似，应似飞鸿踏雪泥，泥上偶然留指爪，鸿飞那复计东西", translation: `同学们，我们来读一读苏轼的这首《和子由渑池怀旧》。诗人在感叹说：人这一生东奔西走、四处漂泊，到底像什么呢？这句写得好，开头就用问句引人思考。接着他说：应该就像那飞翔的大雁，踩在雪地上留下淡淡的脚印吧。泥地上偶尔会留下爪印，可是大雁一飞冲天之后，哪里还会计较自己究竟要飞向东方还是西方呢？这首诗告诉我们，人生就像雪泥上的鸿爪，偶然留下痕迹，转眼便随飞鸿远去，不必过分执着。`, interpretation: `这是苏轼写给弟弟苏辙的诗。当时兄弟俩路过渑池，想起上次住过的寺庙和老和尚已经去世，苏轼有感而发。他用"飞鸿踏雪泥"打比方，说人生就像大雁在雪上踩几脚，痕迹很快就没了。这可比方成了千古名句，后来人们常用"雪泥鸿爪"形容往事留下的淡淡痕迹。苏轼写这首诗时才二十多岁，聪明得不得了，却已经开始思考人生无常这样的大问题啦！` }] },
  { id: 138, title: "琴诗",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "若言琴上有琴声，放在匣中何不鸣，若言声在指头上，何不于君指上听",
    tags: "宋,哲理",
    color: "#06b6d4",
    sections:[    { id: 1, title: "琴诗", original: "若言琴上有琴声，放在匣中何不鸣，若言声在指头上，何不于君指上听", translation: `同学们，我们来读一读宋代苏轼的《琴诗》。这首小诗只有四句，却讲了一个很有意思的道理。现在我们一句一句地看：若言琴上有琴声，放置匣中何不鸣，意思是说，如果琴声是从琴本身发出来的，那把琴放在盒子里，没有人弹，它为什么不会自己响呢？若言声在指头上，何不于君指上听，意思是说，如果声音全在手指上，那你为什么不直接贴在手指上去听，而非要弹琴呢？这句写得好，用两个问句把问题抛出来，让人不禁思考。原来啊，诗人是想告诉我们：美好的琴声，既离不开琴，也离不开弹琴的手指，缺了哪一个都不行。`, interpretation: `这首诗写于宋代，体现了苏轼爱思考、爱提问的性格。那时候的文人喜欢在小事里发现大道理。苏轼从弹琴这件事入手，提出了一个有趣的问题：好听的琴声，到底是琴发出来的，还是手指弹出来的呢？其实他是想告诉大家：世上很多美好的事物，都是不同条件凑在一起才能产生的，缺了一样都不行。这种用小事情讲大道理的方法，后来很多诗人都跟着学呢。` }] },
  { id: 139, title: "东栏梨花",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "梨花淡白柳深青，柳絮飞时花满城，惆怅东栏一株雪，人生看得几清明",
    tags: "宋,感怀",
    color: "#06b6d4",
    sections:[    { id: 1, title: "东栏梨花", original: "梨花淡白柳深青，柳絮飞时花满城，惆怅东栏一株雪，人生看得几清明", translation: `同学们，我们来读一读宋代苏轼的《东栏梨花》。第一句"梨花淡白柳深青"，是说梨花开着淡淡的白花，柳树则长出了深深的青叶。第二句"柳絮飞时花满城"，翻译过来就是：当柳絮随风飘舞的时节，整个城里都飞满了柳絮和纷纷飘落的梨花。这句写得好，用一个"满"字，把春天飞絮飘花、热热闹闹的景象一下子写了出来。接着看第三句"惆怅东栏一株雪"，意思是：诗人怀着淡淡的忧愁，望向东边栏杆旁那一树雪白的梨花，仿佛一团白雪。这句写得好，诗人用一个"雪"字来形容满树梨花，想象十分新奇。最后一句"人生看得几清明"，是说人这一辈子，又能赶上几次这样清明明朗的好春光呢？这是全诗的中心，诗人由眼前的梨花美景，想到了人生短暂，忍不住发出了一声轻轻的感叹。`, interpretation: `这首诗写于北宋，苏轼被贬到徐州时所作。当时他心情郁闷，看到梨花盛开却由繁华联想到易逝。诗人借梨花这一洁白意象，感叹人生美好却短暂。诗中以'淡白'对'深青'、以'柳絮'对'梨花'，色彩鲜明，对仗工整。最妙的是最后一句'人生看得几清明'，既说眼前清明节的春光，也暗指人生中清醒明澈的时刻，用梨花自喻品格高洁，成为千古名句。` }] },
  { id: 140, title: "陌上花",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "陌上花开蝴蝶飞，江山犹是昔人悲，遗民几度垂垂老，游女长歌缓缓归",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "陌上花", original: "陌上花开蝴蝶飞，江山犹是昔人悲，遗民几度垂垂老，游女长歌缓缓归", translation: `同学们，我们来读一读这首《陌上花》。诗人走在田间的小路上，看见路旁花儿开得正好，蝴蝶在花丛中上下飞舞，这本是一幅十分美丽的春天图画。可是诗人的心里并不快乐，因为他想到：眼前的江山依然和从前一样，可当年的人却已不在，怎不叫人伤感？这句写得好，“犹是”二字把景物没变、人事已非的对比写得清清楚楚。接着他又看到，当年的百姓如今已经渐渐老去，头发和胡须都慢慢变得稀疏花白；而年轻一代的姑娘们，却还能无忧无虑地唱着歌，慢悠悠地走回家去。一老一少、一悲一欢，更让人体会到时光流逝的无情。`, interpretation: `这首诗写于北宋，苏轼在杭州任职时，回忆起五代十国时期吴越国的故事。陌上花是当地流传的民间歌谣。诗中'江山犹是昔人悲'最打动人心——同样的山水，却换了几代人，令人感慨。诗的语言像民歌一样朴实好听，蝴蝶飞、姑娘唱歌的画面美丽又带着一丝忧伤。` }] },
  { id: 141, title: "出颍口初见淮山",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "我行日夜向江海，枫叶芦花秋兴长，长淮忽迷天远近，青山久与船低昂",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "出颍口初见淮山", original: "我行日夜向江海，枫叶芦花秋兴长，长淮忽迷天远近，青山久与船低昂", translation: `同学们，我来读一读宋代陆游的这首小诗《出颍口初见淮山》。第一句“我行日夜向江海”，说的是诗人日夜赶路，一心朝着江海的方向前行。第二句“枫叶芦花秋兴长”，意思是岸边的枫叶火红，芦花雪白，正是秋意正浓的时候，所以诗人的兴致也特别高昂。这句写得好，短短七个字就画出秋天最美的色彩！第三句“长淮忽迷天远近”，长长的淮河望不到头，忽然让人分不清天边到底有多远。最后一句“青山久与船低昂”，两岸的青山仿佛跟随着小船一同前行，一会儿好像压低了身子，一会儿又高高昂起头，读起来真让人身临其境呢。`, interpretation: `这首诗写于苏轼被贬赴杭州途中（1071年），船出颍口初入淮河所作。一个被赶路的官员，并没有愁眉苦脸，反而被秋天的枫叶芦花逗得兴致勃勃。你看“青山久与船低昂”多妙——明明是船在水中起伏，青山怎么也跟着一起一落？苏轼把山写活了，仿佛青山是他的老朋友，一路陪伴。这种把静景写成动景的妙笔，正是苏轼写景诗的绝招。后来“低昂”写山的手法被很多人模仿，成了山水诗里的小绝活。` }] },
  { id: 142, title: "有美堂暴雨",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "游人脚底一声雷，满座顽云拨不开，天外黑风吹海立，浙东飞雨过江来",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "有美堂暴雨", original: "游人脚底一声雷，满座顽云拨不开，天外黑风吹海立，浙东飞雨过江来", translation: `同学们，今天我们来读一读苏轼的《有美堂暴雨》。诗人登上西湖边的有美堂，忽然听到脚底下轰的一声响雷，好像雷就在自己身边炸开一样。请大家注意“满座顽云拨不开”这句写得好——满屋子都是又厚又沉的乌云，怎么用手去拨都拨不开，形容天色黑得吓人。接着“天外黑风吹海立”，是说天边刮来阵阵黑风，把钱塘江的海水都吹得像墙壁一样立了起来，多么惊人的气势！最后一句“浙东飞雨过江来”，是说浙江东边的大雨，像长了翅膀一样飞过钱塘江，朝有美堂这边扑来。这四句诗把一场暴雨写得又响、又黑、又猛，让人读着就觉得心惊肉跳，真是气象万千啊。`, interpretation: `这首诗写于北宋熙宁年间，苏轼任杭州通判时。当时杭州常有暴雨，苏轼登上有美堂亲眼所见，兴奋地写下了这首诗。诗中用了"雷声""顽云""黑风""海立""飞雨"这些又猛又急的意象，把一场暴雨写得惊天动地。短短四句里先有声音，再有乌云，然后风卷海水，最后雨从江对岸飞过来，画面一层比一层震撼。"天外黑风吹海立"是千古名句，想象奇特，夸张又生动，让人读了就觉得那场雨好像就下在眼前。` }] },
  { id: 143, title: "西江月·夜行黄沙道中",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "明月别枝惊鹊，清风半夜鸣蝉，稻花香里说丰年，听取蛙声一片",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "西江月·夜行黄沙道中", original: "明月别枝惊鹊，清风半夜鸣蝉，稻花香里说丰年，听取蛙声一片，七八个星天外，两三点雨山前，旧时茅店社林边，路转溪桥忽见", translation: `月光太亮，把树枝上睡觉的喜鹊都给惊动了。清凉的风在半夜里吹过来，知了叫个不停。稻花飘香的时候，蛙声一片，仿佛在说着今年是个丰收年。抬头看天，远处天边只有七八颗星星。几滴小雨飘落在山前。绕过弯弯的山路，那个熟悉的茅草小店就在土地庙的树林旁边，跨过溪上的小桥，一下子就出现在眼前。`, interpretation: `这是辛弃疾晚年住在江西上饶时写的一首小词。1181年他被罢官，闲居农村长达二十年，但这首词里却看不到一丝愁苦，反而处处洋溢着丰收的喜悦和山乡的恬静。词中最妙的是'惊鹊'和'鸣蝉'——一动一静，鸟虫都被月光清风叫醒，说明夏夜多美呀！上片写夜景，用稻花香和蛙声写出了乡村的热闹；下片写走路时的天气变化和突然找到客栈的惊喜，短短几行，就像一幅会动的山水画。读起来像在听一首轻快的小夜曲，让人忍不住想去乡下走一走呢！` }] },
  { id: 144, title: "破阵子·为陈同甫赋壮词以寄之（节选）",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "醉里挑灯看剑，梦回吹角连营，八百里分麾下炙，五十弦翻塞外声，沙场秋点兵，了却君王天下，事赢得生前身，后名可怜白发生",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "破阵子·为陈同甫赋壮词以寄之（节选）", original: "醉里挑灯看剑，梦回吹角连营，八百里分麾下炙，五十弦翻塞外声，沙场秋点兵，马作的卢飞快，弓如霹雳弦惊，了却君王天下事，赢得生前身后名，可怜白发生", translation: `喝醉了酒，点亮油灯，抽出宝剑仔细端详；睡梦中仿佛回到了军营，号角声连成一片。切开牛肉分给部下烤着吃，军乐奏起边塞雄壮的乐曲。秋天沙场上正在检阅军队。战马像的卢一样飞奔，弓弦响处如惊雷劈下。替君王完成收复天下的大业，也为自己赢得生前死后的好名声。可怜啊，头发已经全白了！`, interpretation: `这是南宋大词人辛弃疾写给好友陈亮（字同甫）的词。那时南宋偏安一隅，辛弃疾一心想收复被金人占领的北方，却壮志难酬。他只好借酒浇愁，在梦里重返战场。词中“八百里分麾下炙”“沙场秋点兵”，描绘出军营中烤肉、检阅的豪迈场景，热气腾腾。“马作的卢飞快，弓如霹雳弦惊”一句最是精彩，战马奔腾、弓弦炸响，画面感十足。整首词前半段气势如虹，后半句却笔锋一转，“可怜白发生”——满头白发！豪情壮志都成了梦，多让人心疼啊！` }] },
  { id: 145, title: "永遇乐·京口北固亭怀古（节选）",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "千古江山，英雄无觅，孙仲谋处舞，榭歌台风，流总被雨打风，吹去凭谁，问廉颇老矣尚，能饭否",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "永遇乐·京口北固亭怀古（节选）", original: "千古江山，英雄无觅，孙仲谋处舞，榭歌台风，流总被雨打风，吹去斜阳，草树寻常巷陌，人道寄奴曾想当年，金戈铁，马气吞万里如虎凭，谁问廉颇，老矣尚能，饭否", translation: `千古江山依旧，可英雄像孙权那样的人再也找不到了。当年歌舞繁华的亭台楼阁，总被风吹雨打消散在斜阳里。普通的街巷，人们说刘裕曾在那里住过。想当年他骑着战马、挥着兵器，气势像猛虎一样威猛。如今谁能来问一问：廉颇老了，还能不能吃饭打仗呢？`, interpretation: `这首词写于南宋时期，那时北方已被金人占领，辛弃疾站在京口北固亭上，看着壮丽山河，想起曾经在这里建功立业的英雄豪杰，感慨自己报国无门。词中最精彩的是'金戈铁马，气吞万里如虎'，写英雄刘裕北伐时的威风，读起来让人热血沸腾。最后用老将廉颇的典故，辛弃疾是在问：还有谁关心我老了还能不能为国效力呢？这首词悲壮豪迈，是辛弃疾爱国词中的代表作，后来很多文人都喜欢模仿它的风格。` }] },
  { id: 146, title: "青玉案·元夕（节选）",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "东风夜放花千树，更吹落星，如雨宝马雕，车香满路众里寻，他千百度蓦然回，首那人，却在灯火阑，珊处",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "青玉案·元夕（节选）", original: "东风夜放花千树，更吹落星，如雨宝马雕，车香满路凤箫声，动玉壶光转一夜，鱼龙舞，蛾儿雪柳黄，金缕笑语盈盈暗，香去众里，寻他千百度，蓦然回首那人却，在灯火阑珊处", translation: `东风吹开了夜晚满城的花灯，又吹落了像星星一样、像雨水一样多的灯烛。豪华的马车飘满一路香气，凤箫的乐声四处回荡，月亮转过天空，光影移动，鱼形龙形的花灯欢快地舞动。姑娘们戴着蛾儿、雪柳、黄丝金线做的首饰，笑声轻盈，香味淡淡飘散。我在人群里找了她一遍又一遍，找了一千次、一百次都没找到——一回头，却看见她站在灯火稀少的冷清地方。`, interpretation: `这首词写的是南宋元宵节的热闹场景。那时候国家不太平，可老百姓照样过节，街上张灯结彩，热闹非凡。辛弃疾特别会用一个词把画面点亮——比如"东风夜放花千树"，一个"放"字就好像满树的灯一瞬间全亮了，多热闹啊！整首词从热闹的人群、一眼望不到边的灯会，一直写到最后一个不一样的姑娘，站在灯光照不到的小角落里。这种写法很有名，后来王国维把它比作做大学问的三种境界，最后一种就是"众里寻他千百度，蓦然回首，那人却在灯火阑珊处"——苦苦寻找的东西，原来就在一个不起眼的地方等你呢！` }] },
  { id: 147, title: "丑奴儿·书博山道中壁",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "少年不识，愁滋味爱，上层楼爱，上层楼为，赋新词强，说愁而今，识尽愁滋，味欲说还，休欲说还，休却道天，凉好个秋",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "丑奴儿·书博山道中壁", original: "少年不识，愁滋味爱，上层楼爱，上层楼为，赋新词强，说愁而今，识尽愁滋，味欲说还，休欲说还，休却道天，凉好个秋", translation: `同学们，我们来读一读南宋词人辛弃疾的《丑奴儿》。那时候他还没做官，受了打击，心里很苦闷。一个人走到博山路上，把词写在墙上。年少的他不懂什么叫愁，偏偏喜欢爬上高楼去眺望远方。为了写新词，硬要编出一点“愁”来。其实那时候并不真懂愁啊！而现在呢？尝尽了愁的滋味，想说却说不出来，想说又咽了回去。想来想去，只好说——天气真凉快，秋天真好啊！这句写得好，“天凉好个秋”表面说天气，里头的愁苦全藏在字里行间，正是欲说还休的滋味。`, interpretation: `这首词是辛弃疾被贬官闲居江西时写的，当时他报国无门，心里很苦。他用了一个特别巧妙的对比：小时候不懂愁，还故意上高楼假装忧愁写诗；现在真正愁了，反而说不出来。这种'少年强说愁'和'而今欲说还休'的反差，特别真实地写出了长大后才有的那种深深的无奈。最后一句'却道天凉好个秋'，明明心里愁得很，却只说天气好，这是古人含蓄的表达，也是最让人心酸的地方。这种欲说还休的心情，每个人长大后都会懂。` }] },
  { id: 148, title: "清平乐·村居",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "茅檐低小，溪上青青草，醉里吴音相媚好，白发谁家翁媪，大儿锄豆溪东，中儿正织鸡笼，最喜小儿亡赖，溪头卧剥莲蓬",
    tags: "宋,田园",
    color: "#06b6d4",
    sections:[    { id: 1, title: "清平乐·村居", original: "茅檐低小，溪上青青草，醉里吴音相媚好，白发谁家翁媪，大儿锄豆溪东，中儿正织鸡笼，最喜小儿亡赖，溪头卧剥莲蓬", translation: `茅草盖的屋檐又低又小，溪边长满了绿油油的青草。喝醉了吗？带着吴侬软语的老夫妻正在亲热地说笑。头发都白啦，这是谁家的公公和婆婆呀？大儿子在溪东边给豆田除草呢，二儿子正坐在家里编织鸡笼。最可爱的是那个调皮的小儿子，他正趴在溪边剥着莲蓬吃呢。`, interpretation: `这首词写于辛弃疾晚年闲居江西农村时。那时的他虽然一心想收复中原，却遭排挤，只能在田园里暂时忘却烦恼。词中最动人的就是那对白发老夫妻，他们喝着酒、说着柔媚的吴侬软语，脸上写满了相守一辈子的幸福。整首词像一幅淡淡的水墨画，从茅檐、小溪写到一家五口人，每个人都有事做、都有笑模样，连调皮的小儿子趴在水边剥莲蓬都让人心生欢喜。辛弃疾用最朴素的白描手法，把乡村生活的温暖写得深入人心——原来真正的英雄，笔下也能流淌出最柔软的烟火气。` }] },
  { id: 149, title: "南乡子·登京口北固亭有怀",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "何处望神州，满眼风光，北固楼千古兴亡，多少事悠悠不尽，长江滚滚流",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "南乡子·登京口北固亭有怀", original: "何处望神州，满眼风光，北固楼千古兴亡，多少事悠悠不尽，长江滚滚流，年少万兜鍪，坐断东南，战未休天下英雄，谁敌手曹刘生子，当如孙仲谋", translation: `什么地方能望见中原故土呢？站在亭上放眼望去，满眼都是美好的风景。千古以来，北固楼见证了多少朝代的兴衰更替，那些往事悠悠漫长，怎么也说不完。滚滚长江水向东奔流，永不停歇。想当年，孙权年轻时就统率千军万马，雄踞东南一带，战事从未停歇。天下的英雄豪杰中，谁能做他的对手呢？只有曹操和刘备罢了。生子当如孙仲谋啊！`, interpretation: `这是辛弃疾晚年任职镇江时，登北固亭所作。当时南宋偏安一隅，辛弃疾空有报国之志却屡遭排挤。他登上北固亭，遥望中原故土（神州），眼前的壮丽风景与满腔悲愤交织。他想起三国时孙权年少便据守江东、力敌曹操刘备的英雄事迹，感慨南宋朝廷竟无如此人物。全词以景起兴，以史抒怀，豪迈中透着悲凉。'生子当如孙仲谋'一句流传千古，成为后世父母勉励儿郎的名言。` }] },
  { id: 150, title: "鹧鸪天·代人赋",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "晚日寒鸦一片愁，柳塘新绿却温柔，若教眼底无离恨，不信人间有白头",
    tags: "宋,情感",
    color: "#06b6d4",
    sections:[    { id: 1, title: "鹧鸪天·代人赋", original: "晚日寒鸦一片愁，柳塘新绿却温柔，若教眼底无离恨，不信人间有白头", translation: `同学们，我们来读一读这首词。傍晚时分，夕阳缓缓西沉，天边的寒鸦（天冷时仍在外飞的小乌鸦）一只只飞回巢中，这番苍凉的景象，让人不由得生出一片愁绪。然而转头望去，池塘边的柳树刚刚吐出嫩绿的新芽，那一抹新绿看上去又是那样温柔、那样让人怜爱。这句写得好！一片愁与新绿的温柔形成鲜明对比，恰恰勾出词人心底那份又苦又暖的复杂情感。后两句更深一层：如果一个人眼底没有尝过离别怨恨的滋味，就不会相信这世上真有人会因思念而愁白了头。短短几句，把人间离愁写得既深又真，令人动容。`, interpretation: `这是辛弃疾替人写的一首送别词。南宋时期，许多人因战乱被迫与亲友分离，所以词中的离愁别绪特别动人。词人抓住“寒鸦”和“新绿”两个意象来对比——黄昏的乌鸦让人伤感，早春的柳色却又带来一丝温柔的慰藉。最妙的是后两句：先假设“眼底无离恨”，再说“不信人间有白头”，用反问的语气告诉我们，离别之苦真的能让人愁白了头发。这两句写尽天下离别人的心声，所以流传很广，成为千古名句。` }] },
  { id: 151, title: "采桑子·书博山道中壁",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "少年不识愁滋味，爱上层楼，爱上层楼，为赋新词强说愁",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "采桑子·书博山道中壁", original: "少年不识愁滋味，爱上层楼，爱上层楼，为赋新词强说愁", translation: `同学们，我们来读一读这首词。年轻的时候啊，根本不懂什么叫忧愁。那时候只觉得天是蓝的，云是白的，日子过得无忧无虑。偏偏喜欢爬上高楼，登高望远，望着远方的大好河山，心里充满豪情。为了能写出新词，硬是把愁啊愁的往诗里塞。其实啊，那时候的愁是装出来的，并不是真正体会到了愁苦的滋味。这句写得好，它告诉我们，少年时代的所谓忧愁，多半是无病呻吟，是为了写诗作文而勉强装出来的。`, interpretation: `这首词写于辛弃疾中年被贬闲居时期，那时他被排挤出朝廷，报国无门，心情郁闷。回忆起年少时光，他觉得那时候的自己天真可爱——根本没经历过真正的愁苦，却为了写出漂亮的词，硬要装出忧愁的样子。词中“层楼”重复出现，读起来像是在叹气，特别有味道。这几句流传很广，常被用来形容那种“为写文章而假装深刻”的小大人心态，特别有趣。` }] },
  { id: 152, title: "菩萨蛮·书江西造口壁",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "郁孤台下清江水，中间多少行人泪，西北望长安，可怜无数山，青山遮不住，毕竟东流去",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "菩萨蛮·书江西造口壁", original: "郁孤台下清江水，中间多少行人泪，西北望长安，可怜无数山，青山遮不住，毕竟东流去，江晚正愁余，山深闻鹧鸪", translation: `郁孤台下滚滚流过的清江水，这水中啊，融入了多少逃难百姓的泪水。我抬头向西北眺望故都汴京的方向，可惜被层层叠叠的山岭挡住了视线。青山虽然挡住了我的目光，却挡不住滔滔江水向东奔流。到了傍晚江边，我正满心忧愁，又听见深山里传来鹧鸪鸟的叫声。`, interpretation: `这首词写于1129年，那时金兵入侵江西，百姓四处逃亡，辛弃疾路过郁孤台，想起这段惨痛历史，满怀悲愤。词中“清江水”象征着人民的泪水，“无数山”暗喻阻隔收复中原的重重困难，而江水“毕竟东流去”则表达了词人坚定的信念——任何力量都阻挡不了收复失地的决心。下阕的“鹧鸪声”在古诗中常代表“行不得也”，更添愁绪。整首词短短八句，融家国之痛与个人情怀于一体，沉郁悲壮，是辛弃疾早期爱国词的代表作，其中“青山遮不住，毕竟东流去”流传千古，成为激励人们冲破阻碍的名句。` }] },
  { id: 153, title: "卜算子·咏梅",
    author: "陆游",
    dynasty: "宋",
    category: "宋",
    summary: "驿外断桥边，寂寞开无主，已是黄昏独自愁，更著风和雨，无意苦争春，一任群芳妒，零落成泥碾作尘，只有香如故",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "卜算子·咏梅", original: "驿外断桥边，寂寞开无主，已是黄昏独自愁，更著风和雨，无意苦争春，一任群芳妒，零落成泥碾作尘，只有香如故", translation: `在驿站外面的断桥旁边，一棵梅花静静地开放，没有人照料。已经到了黄昏时分，它独自忧愁，偏偏又遭到风雨的欺负。它从不想苦苦争夺春光，随便别的花儿去嫉妒吧。即使花瓣凋落变成泥土，又被碾成灰尘，它的香气依然和从前一样。`, interpretation: `这首词写于陆游晚年，当时他闲居故乡，怀才不遇。词中那株开在断桥边、无人欣赏、风中独立、最后零落成泥的梅花，正是他自己的化身。他借梅花表达了一种非常高洁的品格：不需要和别人争抢光彩，哪怕被排挤、被摧残，只要内心的香气还在，就什么都不怕。最后一句"只有香如故"成了千古名句，激励着无数在困境中坚持自我的人，是中国人最爱的精神象征之一。` }] },
  { id: 154, title: "临安春雨初霁",
    author: "陆游",
    dynasty: "宋",
    category: "宋",
    summary: "世味年来薄似纱，谁令骑马客京华，小楼一夜听春雨，深巷明朝卖杏花",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "临安春雨初霁", original: "世味年来薄似纱，谁令骑马客京华，小楼一夜听春雨，深巷明朝卖杏花，矮纸斜行闲作草，晴窗细乳戏分茶，素衣莫起风尘叹，犹及清明可到家", translation: `这些年做官的味道淡得像一层薄纱，是谁让我骑着马来京城做客客居他乡？住在小楼里听了一整夜的春雨滴答，想着明天清晨深巷里会传来叫卖杏花的声音。闲来无事，铺开矮纸歪歪斜斜地练起草书来；雨过天晴，在窗下慢慢地煮茶、品茶。白衣裳不要去感叹会被风尘染脏，还来得及呀，赶在清明节前我就能回到家乡。`, interpretation: `这首诗写于宋孝宗淳熙十三年，陆游六十二岁，在京城临安（今杭州）等候调任。多年的仕途让他觉得做官没什么意思，所以开篇就抱怨“谁令骑马客京华”——不是自己想来，是被迫来的。“小楼一夜听春雨，深巷明朝卖杏花”是最有名的句子，一个写夜里听雨、一个想象清晨卖花，安静又带着淡淡的春愁，是宋诗里写春雨的名句。诗人闲得无聊，只好写字、分茶打发时间。最后说清明前还能赶回家透露出想回乡的心情。这首诗把一个老人等官做的无聊劲儿写得特别生动，连发呆都透着一股清雅的诗意。` }] },
  { id: 155, title: "书愤",
    author: "陆游",
    dynasty: "宋",
    category: "宋",
    summary: "早岁那知世事艰，中原北望气如山，楼船夜雪瓜洲渡，铁马秋风大散关",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "书愤", original: "早岁那知世事艰，中原北望气如山，楼船夜雪瓜洲渡，铁马秋风大散关，塞上长城空自许，镜中衰鬓已先斑，出师一表真名世，千载谁堪伯仲间", translation: `年轻时哪里懂得世事的艰难,北望中原,胸中豪气如山一样磅礴。回想当年,瓜洲渡口战船在夜雪中出击,大散关下铁马在秋风中驰骋。我曾自许是守边的万里长城,如今照镜子,鬓发已经斑白。诸葛亮的《出师表》名传天下,千年来有谁能和他相比呢?`, interpretation: `这是南宋爱国诗人陆游晚年写下的名篇。当时北方已被金人占领,南宋偏安一隅,陆游一辈子都想着收复中原,却壮志难酬。这首诗最厉害的地方是中间四句——夜雪、瓜洲渡、秋风、大散关,短短十六个字,就像四幅画,既有画面又有声音,把过去的战斗场面写得激动人心。可惜呀,诗人年轻时立下的报国誓言,到老了还没实现,只能对着镜子叹白发。结尾他提到三国时的诸葛亮,其实是在说自己也想做那样的忠臣。'楼船夜雪瓜洲渡,铁马秋风大散关'这两句特别有名,后来写边塞打仗的诗人都爱学他。` }] },
  { id: 156, title: "沈园",
    author: "陆游",
    dynasty: "宋",
    category: "宋",
    summary: "城上斜阳画角哀，沈园非复旧池台，伤心桥下春波绿，曾是惊鸿照影来",
    tags: "宋,情感",
    color: "#06b6d4",
    sections:[    { id: 1, title: "沈园", original: "城上斜阳画角哀，沈园非复旧池台，伤心桥下春波绿，曾是惊鸿照影来", translation: `城墙上的夕阳斜斜照着，号角声听起来真叫人难过。
沈园已经不是从前的样子啦，池塘楼台都变了样。
桥下春天的水波绿得让人伤心，
因为过去曾有一位美人，像飞燕一样美丽的身影，在这里对着水波照过自己的影子呢。`, interpretation: `这首诗写于南宋，那时陆游已七十多岁，回到绍兴沈园，想起年轻时和前妻唐婉在这里相爱的情景，可惜唐婉早已离世。诗中最动人的就是“惊鸿照影”四个字——把唐婉比作曹植《洛神赋》里凌波微步的仙子，一个回头就让人记了一辈子。沈园的春天依旧绿水荡漾，可物是人非，斜阳、号角、伤心，三个词连在一起，把老人的思念写得又温柔又心酸。后来“沈园”也成了中国文学里“错过与怀念”的代名词。` }] },
  { id: 157, title: "如梦令",
    author: "李清照",
    dynasty: "宋",
    category: "宋",
    summary: "常记溪亭日暮，沉醉不知归路，兴尽晚回舟，误入藕花深处，争渡，争渡，惊起一滩鸥鹭",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "如梦令", original: "常记溪亭日暮。沈醉不知归路。兴尽晚回舟，误入藕花深处。争渡。争渡。惊起一滩鸥鹭。", translation: `常常想起那次在溪边的亭子玩到太阳落山的时候。喝得醉醺醺的，都找不到回家的路了。玩到尽兴才划船回去，天已经晚了，小船不小心划进了一片荷花深处。大家使劲地划呀划呀，想赶紧出去。结果把水滩上的一群鸥鸟和白鹭全都惊飞起来了。`, interpretation: `这是李清照少女时期的作品，写的是一次郊游的快乐小插曲。词里藏着几个特别美的画面：傍晚的溪亭、醉醺醺的心情、划着小船、还有一大片荷花和被惊飞的鸟。这首词最厉害的地方就是短短几句话，让人好像跟着她一起坐上了那只小船，听到了划水声和鸟扑棱翅膀的声音。结尾连用两个“争渡”，就像我们着急时的语气，读起来特别有劲儿。这首词让人们知道，李清照年轻时也是个爱玩爱闹、活泼可爱的小姑娘呢！` }] },
  { id: 158, title: "声声慢（节选）",
    author: "李清照",
    dynasty: "宋",
    category: "宋",
    summary: "寻寻觅觅，冷冷清清，凄凄惨惨戚戚，乍暖还寒时候，最难将息，梧桐更兼细雨，到黄昏点点滴滴，这次第，怎一个愁字了得",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "声声慢（节选）", original: "寻寻觅觅，冷冷清清，凄凄惨惨戚戚，乍暖还寒时候，最难将息，三杯两盏淡酒，怎敌他晚来风急，雁过也，正伤心却是旧时，相识满地，黄花堆积，憔悴损如今有，谁堪摘梧桐更，兼细雨到，黄昏点点滴滴，这次第怎一个愁，字了得", translation: `我到处寻找又寻找，四周冷冷清清，让人觉得又悲凉又难过。天气刚刚转暖却又变冷的时候，最难安稳休息。喝上几杯淡淡的酒，怎么能抵挡傍晚又大又急的寒风？抬头看见大雁飞过，哎呀，这雁儿我以前见过呀！地上到处是掉落的菊花，枯萎凋零，如今还有谁能去摘呢？偏偏这时又下起了小雨，雨滴打在梧桐叶上，从黄昏一直滴到天黑，一声接一声。这样的光景，一个"愁"字怎么能够说得清呢？`, interpretation: `这首词写于李清照晚年，那时金兵南下、北宋灭亡，她与丈夫赵明诚也阴阳两隔，一个人孤零零地逃难到南方。所以词里没有一点热闹劲儿，全是冷冷清清的。最妙的是开头的十四个叠字——"寻寻觅觅，冷冷清清，凄凄惨惨戚戚"，一口气说出来，像叹气一样，把那种孤单难过的心情写得特别生动。后面"梧桐更兼细雨，到黄昏点点滴滴"，用梧桐叶加上黄昏的雨声来写愁，特别有意境，连后来的电视剧都爱用这句当背景。这种把"愁"写得既真实又优美的手法，让这首词成了千古名篇。` }] },
  { id: 159, title: "渔家傲",
    author: "李清照",
    dynasty: "宋",
    category: "宋",
    summary: "天接云涛连晓雾，星河欲转千帆舞，仿佛梦魂归帝所，闻天语殷勤问我，归何处，我报路长嗟日暮，学诗谩有惊人句，九万里风鹏正举，风休住蓬舟吹取，三山去",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "渔家傲", original: "天接云涛连晓雾，星河欲转千帆舞，仿佛梦魂归帝所，闻天语殷勤问我，归何处，我报路长嗟日暮，学诗谩有惊人句，九万里风鹏正举，风休住蓬舟吹取，三山去", translation: `天空连接着翻滚的云涛，一直延伸到清晨的雾气里。银河仿佛要转动起来，千万只船帆在风里飞舞。我好像在梦中回到了天帝居住的地方，听见天帝亲切地问我：要回到哪里去呢？我回答说：路途太远太长了，又叹息天色已经黄昏。我学写诗歌，空有惊人的句子。狂风正托举着大鹏鸟高高飞起，风啊请不要停，把我这蓬草一样的小船吹到那传说中的三仙山去吧！`, interpretation: `这是李清照南渡之后写的一首奇特的词。那时候她经历了国破家亡，一个人在南方漂泊，心里又苦闷又不甘心。整首词写了一个飞天的梦：她驾着云雾飞过银河，去到天帝的宫殿，天帝问她要去哪里，她却回答说路远天晚、流落无归。这是用梦境来说心里话——现实中她无处可去，只能把希望寄托在神话里。这首词最特别的地方，是把豪放派常用的“大鹏展翅”“风举飞舟”写进了婉约词人的笔下，气魄宏大、想象瑰丽。'九万里风鹏正举'一句后来广为传诵，李清照也因此被大家称为'婉约词宗'，却也能写出这样气势磅礴的作品，十分了不起。` }] },
  { id: 160, title: "武陵春",
    author: "李清照",
    dynasty: "宋",
    category: "宋",
    summary: "风住尘香花已尽，日晚倦梳头物是，人非事事休欲语，泪先流闻说双溪，春尚好也拟泛轻，舟只恐双溪舴艋，舟载不动许多愁",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "武陵春", original: "风住尘香花已尽，日晚倦梳头物是，人非事事休欲语，泪先流闻说双溪，春尚好也拟泛轻，舟只恐双溪舴艋，舟载不动许多愁", translation: `风停了，花儿都落了，泥土里还留着香气。太阳老高了，我却懒得梳头。东西还是老样子，人却变了，一切事情都算完了。想说点什么，眼泪就先流下来了。听说双溪的春光还不错，我也打算去划划小船。可是又怕那双溪的小船太轻太小，装不下我心里这么多的忧愁啊。`, interpretation: `这首词写于李清照丈夫赵明诚去世之后，是她漂泊江南时的心声。那时候国破家亡，亲人离散，她一个柔弱女子扛不住这许多打击。词里最妙的是结尾——她不说愁多，只说小船装不动，化无形为有形，愁一下子就有了重量，成了看得见摸得着的东西。这种写法叫“以小见大”，后来很多人写愁都会学她，比如说愁像一江春水啦、像一川烟草啦，都是从这个思路上来的。读这首词，你会发现一个特别真实、特别勇敢的李清照，她不装坚强，只是老老实实告诉你：我很难过。` }] },
  { id: 161, title: "醉翁亭记（节选）",
    author: "欧阳修",
    dynasty: "宋",
    category: "宋",
    summary: "醉翁之意不在酒在乎山水之间也山水之乐得之心而寓之酒也",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "醉翁亭记（节选）", original: "环滁皆山也其西，南诸峰林壑尤美，渐闻水声潺潺而，泻出于两峰之间，者酿泉也峰回路，转有亭翼然临于，泉上者醉翁亭也，醉翁之意不在酒，在乎山水之间也", translation: `环绕着滁州城的四面都是山。它西南方向的几座山峰，树林和山谷特别美丽。渐渐听到潺潺的水声，（水流）从两座山峰之间奔泻而下的，就是酿泉。山势回环，路也跟着拐弯，有座亭子四角翘起，像鸟儿张开翅膀一样，高踞在泉水边上，这就是醉翁亭。醉翁的心意不在喝酒上，而是在乎这里的山山水水啊。`, interpretation: `这是欧阳修被贬到滁州当太守时写的，那时候他心里有点郁闷，但滁州山清水秀，让他心情舒畅了不少。他用“环滁皆山”开头，一下子就把我们带进了一个被群山环抱的小城。然后他像导游一样，牵着我们的手，一路走一路介绍：听，泉水声！看，山路转弯处有座漂亮的亭子！最有意思的是那句“醉翁之意不在酒”，本来是说他自己，其实我们小朋友也一样——玩的时候最高兴的，往往不是玩具本身，而是和小伙伴在一起的快乐时光。这篇文章让“醉翁亭”成了千古名亭，连欧阳修喝的泉水都跟着出名啦！` }] },
  { id: 162, title: "生查子·元夕",
    author: "欧阳修",
    dynasty: "宋",
    category: "宋",
    summary: "去年元夜时，花市灯如昼，月上柳梢头，人约黄昏后，今年元夜时，月与灯依旧，不见去年人，泪满春衫袖",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "生查子·元夕", original: "去年元夜时，花市灯如昼，月上柳梢头，人约黄昏后，今年元夜时，月与灯依旧，不见去年人，泪满春衫袖", translation: `去年的元宵节那天，街上的花灯亮得跟白天一样。月亮慢慢爬上了柳树的枝头，我约好的人在黄昏之后来见面。今年的元宵节又到了，月亮还是那个月亮，花灯还是那样亮，可是去年那个人却看不见了。难过的眼泪把我春天的衣袖都沾湿了。`, interpretation: `这首词写于宋代，那时候元宵节是一年里最热闹的节日之一，街上挂满花灯，年轻的男女也可以出门游玩。欧阳修写的'月上柳梢头，人约黄昏后'特别美——月亮爬上柳树，相约在黄昏以后，成了千古流传的名句。词的上半段是甜的，下半段是酸的，同一个元宵节，同样的月亮和花灯，偏偏少了那个人。这种'去年'和'今年'的对比写法，后来很多人学着用，连大词人辛弃疾都模仿过，读起来让人心里又甜又酸。` }] },
  { id: 163, title: "蝶恋花",
    author: "欧阳修",
    dynasty: "宋",
    category: "宋",
    summary: "庭院深深深几许，杨柳堆烟，帘幕无重数，泪眼问花花不语，乱红飞过秋千去",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "蝶恋花", original: "庭院深深深几许，杨柳堆烟，帘幕无重数，玉勒雕鞍游冶处，楼高不见章台路，雨横风狂三月暮，门掩黄昏，无计留春住，泪眼问花花不语，乱红飞过秋千去", translation: `庭院幽深，到底有多深呢？杨柳被一层层雾气笼罩，像堆起了轻烟。帘幕多得数也数不清。豪华马车停留的地方，是公子哥们寻欢作乐之处。楼再高，也望不见通往那条路的方向。三月傍晚，风雨又急又猛。关上院门，掩住黄昏的暮色，却想不出办法把春天留住。泪眼汪汪地问花儿，花儿却默默不语。零乱的落花一片片飞过秋千，飘向远方。`, interpretation: `这首词写于宋代，欧阳修借一位深闺女子的眼睛，描绘了一个春雨黄昏的孤独时刻。词中最妙的是三个"深"字连用——"深深深几许"，像小朋友在追问：到底有多深呀？一下子把院子的幽深和心里的寂寞都写出来啦。"泪眼问花花不语"是千古名句：人问花，花不答，只有飘落的红花瓣飞过秋千。这画面又美又伤感，奠定了中国古典诗词中"以花喻人"的传统，后来李清照、曹雪芹都从这儿得到灵感呢！` }] },
  { id: 164, title: "画眉鸟",
    author: "欧阳修",
    dynasty: "宋",
    category: "宋",
    summary: "百啭千声随意移，山花红紫树高低，始知锁向金笼听，不及林间自在啼",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "画眉鸟", original: "百啭千声随意移，山花红紫树高低，始知锁向金笼听，不及林间自在啼", translation: `画眉鸟一会儿飞到这里，一会儿飞到那边，叫声婉转动听，千变万化。山野里，红的紫的山花到处都是，有的开在高高的树上，有的开在低矮的枝头。可是后来把它关进华贵的金笼子里，再听它啼叫，才知道远比不上在树林里自由欢唱时那么动听啊。`, interpretation: `这首诗写于北宋，欧阳修当时被贬，心情郁闷。他在朝廷做官时，就像被关进金笼子的画眉鸟一样，处处受拘束；相比之下，山野林间虽然简朴，却能自由自在地歌唱。诗中"红紫"山花和"高低"树木的彩色画面，是画眉鸟生活的美好背景，"百啭千声"则写出鸟儿在林中欢快歌唱的活泼样子。他用对比的方法告诉我们：再华丽的环境，如果没有自由，也比不上朴实却自在的生活。` }] },
  { id: 165, title: "丰乐亭游春",
    author: "欧阳修",
    dynasty: "宋",
    category: "宋",
    summary: "红树青山日欲斜，长郊草色绿无涯，游人不管春将老，来往亭前踏落花",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "丰乐亭游春", original: "红树青山日欲斜，长郊草色绿无涯，游人不管春将老，来往亭前踏落花", translation: `同学们，我们来读一读北宋文学家欧阳修的《丰乐亭游春》。这首诗写的是诗人在丰乐亭旁看到的春日景色。红艳的树林和青青的山峦，在夕阳的映照下显得格外美丽，太阳快要落下山了。这句写得好，用“红树”和“青山”两种颜色，把傍晚的山水点染得五彩缤纷。广阔的郊外，草色绿油油的，一直铺向天边，好像没有尽头一样。一个“绿无涯”，让人感到春天勃勃的生机。接着看，游春的人们啊，根本不在意春天就要老去，仍然在丰乐亭前来来往往，脚下踩着纷纷飘落的春花。这“踏落花”三个字最有意趣——花瓣铺满小路，游人却不舍得离去，浓浓的惜春之情全在这轻轻的一脚之中。`, interpretation: `这首诗写于欧阳修被贬滁州期间，他在山上修建了丰乐亭，常与百姓同游共乐。诗中最美的是色彩：红树、青山、绿草、黄花，像一幅春天的油画。诗人表面说游人不管春将老，其实是他自己珍惜每一刻春光，不肯让烦恼坏了心情。这种豁达乐观的心境，让整首诗读起来轻松又温暖，也成为宋诗中写春的名篇。` }] },
  { id: 166, title: "桂枝香·金陵怀古（节选）",
    author: "王安石",
    dynasty: "宋",
    category: "宋",
    summary: "登临送目，正故国晚秋，天气初肃，千里澄江，似练翠峰如簇",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "桂枝香·金陵怀古（节选）", original: "登临送目，正故国晚秋，天气初肃，千里澄江，似练翠峰如簇征，帆去棹残阳里背，西风酒，旗斜矗彩舟云，淡星河鹭，起画图难足", translation: `登上高处眺望远方，送走目光所及的景色。这正是金陵古都的深秋时节，天气刚刚开始变得清冷肃杀。千里长江清澈见底，像一条白色的绸带；翠绿的山峰层层叠叠，像一束束聚在一起。远行的船只来来往往，船桨划动，夕阳映照在江面上。酒楼的旗子在斜风中飘扬，彩绘的船只点缀在云淡的天空，银河（鹭）飞翔起来，这幅美丽的图画难以用笔墨形容。`, interpretation: `这首词是王安石在金陵（即南京）登高怀古时所作。词中描绘了深秋时节南京长江的壮丽景色：清澈的江水、连绵的青山、往来的船只、飘扬的酒旗和飞翔的白鹭，构成了一幅色彩斑斓的秋江图。词人借景抒情，在欣赏美景的同时，暗含对历史兴亡的感慨。王安石是著名的政治家、文学家，这首词气势恢宏，意境开阔，是宋词中怀古词的经典之作。其中描绘江景的名句传诵千古，展现了词人卓越的写景功力。` }] },
  { id: 167, title: "闲居初夏午睡起",
    author: "杨万里",
    dynasty: "宋",
    category: "宋",
    summary: "梅子留酸软齿牙，芭蕉分绿与窗纱，日长睡起无情思，闲看儿童捉柳花",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "闲居初夏午睡起", original: "梅子留酸软齿牙，芭蕉分绿与窗纱，日长睡起无情思，闲看儿童捉柳花", translation: `同学们，我们来读一读这首诗。诗中说：我刚刚吃完梅子，嘴里还留着那股酸溜溜的味道，连牙齿都被酸得软软的了。这句写得好，一个“留酸软齿牙”，就把初夏尝梅的有趣感觉写出来了。接着看，院子里的芭蕉长得正旺，那一片片大叶子把浓浓的绿色映在了纱窗上，仿佛把绿意也分给了窗户，让整个房间都变得清凉起来。夏天白昼变长了，我午睡醒来后，有些无精打采，也没有什么特别要想的心事。这句“无情思”，写的就是那种懒洋洋的感觉。正好没什么事，我就悠闲地坐在窗边，看着院子里的小孩子们跑来跑去，兴高采烈地追逐着漫天飞舞的柳花，多么自在快乐呀！`, interpretation: `这首诗写于南宋时期，杨万里晚年闲居故乡。他用最普通的家常小景——梅子、芭蕉、柳絮，串起一幅初夏午后的悠闲图。梅子酸、芭蕉绿、柳花飞，三个小细节把夏天的味道、颜色和动感全写活了。最妙的是最后一句，一个大人懒洋洋地看着孩子们疯跑捉柳絮，自己也好像变回了小孩子。这正是杨万里最擅长的小诗风格：不用典、不说理，就像跟你拉家常一样亲切。后人常说他的诗'有孩子气'，读来让人心里也跟着慢下来、清凉下来。` }] },
  { id: 168, title: "四时田园杂兴·其三十一",
    author: "范成大",
    dynasty: "宋",
    category: "宋",
    summary: "昼出耘田夜绩麻，村庄儿女各当家，童孙未解供耕织，也傍桑阴学种瓜",
    tags: "宋,田园",
    color: "#06b6d4",
    sections:[    { id: 1, title: "四时田园杂兴·其三十一", original: "昼出耘田夜绩麻，村庄儿女各当家，童孙未解供耕织，也傍桑阴学种瓜", translation: `同学们，我们来读一读这首诗。白天，农人们迎着朝阳出门，到田里去除草松土；到了夜晚，他们又借着油灯的光辉，坐在家中把麻搓成线。村里的年轻男女呀，没有一个闲着的，他们各自分担着家中的活儿，耕田的耕田，织布的织布，样样都拿得起来。最有趣的是那些还不太懂事的小娃娃，他们虽然还不会耕田，也不会织布，却有模有样地学着长辈的样子，跑到村边大桑树的绿荫下，认认真真地种起小瓜来。这句写得好！一个“学”字，把孩子们的天真可爱和勤劳模样全写出来了，读来让人忍不住会心一笑。`, interpretation: `这首诗写于南宋，那时候战乱较多，但农村生活依然充满生机。范成大晚年回到家乡，亲眼看到乡村里无论大人小孩都在勤劳忙碌，心里很感动。诗中最有趣的就是最后两句——小朋友虽然还不会种地织布，却已经学着大人种瓜了！这种“天真勤劳”的画面特别可爱，让整首诗一下子活了起来。范成大擅长用朴实的话写田园美景，这首小诗就像一幅乡村风俗画，后来还被选进小学课本，成为孩子们最熟悉的古诗之一呢！` }] },
  { id: 169, title: "四时田园杂兴·其二十五",
    author: "范成大",
    dynasty: "宋",
    category: "宋",
    summary: "梅子金黄杏子肥，麦花雪白菜花稀，日长篱落无人过，惟有蜻蜓蛱蝶飞",
    tags: "宋,田园",
    color: "#06b6d4",
    sections:[    { id: 1, title: "四时田园杂兴·其二十五", original: "梅子金黄杏子肥，麦花雪白菜花稀，日长篱落无人过，惟有蜻蜓蛱蝶飞", translation: `同学们，我们来读一读这首诗。四月到了，梅子已经金黄金黄，挂满了枝头；杏子也长得又大又肥，让人看了真想吃一口。同学们，这句写得好啊，短短两句就把夏天果树上丰收的景象写了出来。往田野里看去，小麦开着雪白的花，而油菜花呢，已经开过了头，变得稀稀落落。大家想想看，这时候该是农家人最忙的时候了吧？可诗里却写，白天越来越长了，篱笆边上却安安静静，没有一个人走过。这是怎么回事呢？原来农人们都到田间忙活去了，村子里反而空空荡荡的。最后一句最有趣：只有蜻蜓和蝴蝶在自由自在地飞来飞去，像是在看守着这座安静的村庄。这首诗的妙处就在这里，它写出了乡村初夏时分的宁静和美丽。`, interpretation: `这首诗是南宋大诗人范成大写的，他特别爱写农村生活，写了好多首《四时田园杂兴》，就像给一年四季的农村拍了写真集。这一首拍的是初夏的景色：梅子黄、杏子肥、麦花白、菜花稀，四种颜色、两种果实，一看就知道是江南四五月的样子。'日长'说明夏天到了，白天变长，可农活忙完了，人都歇下了，篱笆边安安静静的，只有蜻蜓蝴蝶来凑热闹。一个'惟有'用得特别妙——不是没人，是人休息了，小虫子们就出来当主角啦，画面一下子就活了。后来很多人写田园诗，都会学范成大这种把庄稼和虫子一起写、特别接地气的方法。` }] },
  { id: 170, title: "喜晴",
    author: "范成大",
    dynasty: "宋",
    category: "宋",
    summary: "窗间梅熟，落蒂墙下，笋成出林，连雨不知，春去一晴，方觉夏深",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "喜晴", original: "窗间梅熟，落蒂墙下，笋成出林，连雨不知，春去一晴，方觉夏深", translation: `同学们，我们来读一读这首小诗《喜晴》。你看，窗前的梅子悄悄熟透了，带蒂的小果子一颗一颗从枝头落下来；墙根底下的小竹笋也不知不觉钻出土，长成了一片青翠的小竹林。雨淅淅沥沥连着下了好多天，让人浑然不觉春天已经悄悄走了；直到今天云开日出、天一下子放晴，才恍然发现，原来夏天已经不知不觉走到深处啦。这句写得好！一个“方觉”，就把那种突然回过神来、惊喜又略带惊讶的感觉写了出来。整首诗虽短，却藏着大自然的悄悄话：时光就在花落笋长、雨去晴来之间偷偷溜走，所以我们要珍惜每一个好天气呀。`, interpretation: `这首小诗出自南宋诗人范成大之手，写的是初夏雨后初晴的小惊喜。短短六句，就像一组生活小镜头：窗前梅子掉落、墙边竹笋成林，从细微之处把季节变换写得活灵活现。最妙的是最后两句——连着下雨让人忘了春天已经过去，直到太阳出来才恍然大悟“原来夏天都这么深了”，这种恍然大悟的感觉，小朋友肯定也体验过！整首诗语言朴素，不堆砌华丽辞藻，就像说话一样自然，却把时间悄悄溜走的意思讲得特别生动，是宋诗里“平淡见真味”的好例子。` }] },
  { id: 171, title: "岳阳楼记（节选）",
    author: "范仲淹",
    dynasty: "宋",
    category: "宋",
    summary: "先天下之忧而忧后天下之乐而乐不以物喜不以己悲",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "岳阳楼记（节选）", original: "予观夫巴，陵胜状在，洞庭一湖，衔远山吞，长江浩浩，汤汤横无，际涯朝晖，夕阴气象，万千先天，下之忧而，忧后天下，之乐而乐", translation: `我看那巴陵郡最壮丽的景色，全在这洞庭湖上啊！它含着远处的山，吞下滚滚的长江，水势浩大，无边无际。清晨阳光明媚，傍晚暮色苍茫，景色真是变化万千。（至于那些不同景色引发的感触，）我以前已经说得很详细了。但是呢——有一种品格值得敬佩，那就是：做官的人，要在天下人忧愁之前先忧愁，在天下人享乐之后才享乐。`, interpretation: `这段话出自范仲淹的《岳阳楼记》，写于北宋时期。当时范仲淹被贬到外地，却仍惦记着国家大事。洞庭湖'衔远山、吞长江'的描写特别生动——一个'衔'字、'吞'字，把湖水的磅礴气势写活了，让人读着就像站在湖边。最精彩的当属最后那句'先天下之忧而忧，后天下之乐而乐'，已经成为千古名句，意思是：好官应该把百姓的冷暖放在心上，自己吃苦在前、享乐在后。这种心怀天下的精神，影响了后来无数的仁人志士，连老师、家长都爱用这句话来教导孩子呢！` }] },
  { id: 172, title: "鹊桥仙",
    author: "秦观",
    dynasty: "宋",
    category: "宋",
    summary: "两情若是久长时，又岂在朝朝暮暮",
    tags: "宋,爱情",
    color: "#06b6d4",
    sections:[    { id: 1, title: "鹊桥仙", original: "纤云弄巧飞星传，恨银汉迢迢暗度，金风玉露一相逢，便胜却人间无数，柔情似水佳期如，梦忍顾鹊桥归路，两情若是久长时，又岂在朝朝暮暮", translation: `轻柔的云彩玩弄着织女的巧手，闪动的流星传递着相思的愁绪。牛郎织女悄悄渡过那遥远的银河，在这秋风白露的美好时刻相逢一次，就胜过人间的无数次相会。温柔的情感像流水一样绵绵，相会的时光像梦一样美好。怎忍心回头看那鹊桥归去的路呢。只要两人之间的真情能够长长久久，又哪里在于朝朝暮暮都在一起呢？`, interpretation: `这首词写于北宋，秦观借牛郎织女七夕相会的传说，歌颂了真挚不渝的爱情。词中最打动人的是下片：相会的时光虽短如梦，归去的鹊桥路虽令人难舍，但只要感情长久，何必贪图天天厮守呢？这一句打破了世俗对朝夕相伴的执念，让爱情升华为一种精神上的契合，境界高远，成为千古名句。它告诉我们：真爱的分量，不在时间的长短，而在心的相通。` }] },
  { id: 173, title: "春日",
    author: "秦观",
    dynasty: "宋",
    category: "宋",
    summary: "一夕轻雷落万丝，霁光浮瓦碧参差，有情芍药含春泪，无力蔷薇卧晓枝",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "春日", original: "一夕轻雷落万丝，霁光浮瓦碧参差，有情芍药含春泪，无力蔷薇卧晓枝", translation: `同学们，我们来读一读宋代诗人秦观的这首《春日》。先看第一句：夜里，天上响起轻轻的雷声，紧接着无数条雨丝像丝线一样从天空飘落下来。第二天早晨，雨停了，太阳出来了，阳光照在屋顶的琉璃瓦上，瓦片上的颜色绿得深深浅浅，格外好看。再看第三句，这句写得好！芍药花的花瓣上还挂着清晨的雨水，看起来就像含着春天伤心的眼泪一样。第四句更有趣，蔷薇花细细的枝条软绵绵的，花朵好像没有力气似的，静静地躺在早晨的枝头。整首诗只用了四种春天的景物，却写出了雨后清晨那种又清新又柔美的感觉，真是妙极了。`, interpretation: `这首诗是宋代词人秦观写的，描绘的是雨后清晨的小院春景。北宋时期，文人很喜欢观察自然、品味生活，秦观更是写景抒情的高手。诗里有四个可爱的春天小明星：轻雷、雨丝、阳光、芍药和蔷薇。诗人特别厉害的地方是用了'含春泪''卧晓枝'这样的写法，明明花和人是两种东西，却说芍药像在哭、蔷薇像在躺着撒娇，这就是'拟人'的魔法，让花儿都有了小脾气、小情绪，读起来特别亲切。这首诗虽然短小，却像一幅精美的工笔画，流传很广，'有情芍药含春泪'一句尤其被人喜爱。` }] },
  { id: 174, title: "苏幕遮",
    author: "周邦彦",
    dynasty: "宋",
    category: "宋",
    summary: "燎沉香，消溽暑，鸟雀呼晴，侵晓窥檐语，叶上初阳干宿雨，水面清圆，一一风荷举",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "苏幕遮", original: "燎沉香，消溽暑，鸟雀呼晴，侵晓窥檐语，叶上初阳干宿雨，水面清圆，一一风荷举", translation: `点燃沉香，让浓浓的香气飘散，把闷热的暑气赶走。雨停了，天晴了，小鸟一大早就叽叽喳喳地叫着，探头探脑地在屋檐下说话。太阳刚升起来，照在荷叶上，把昨夜留下的雨珠慢慢晒干了。水面上，荷叶又青又圆又干净，一朵朵被风轻轻托起，高高地挺立着。`, interpretation: `这是宋代大词人周邦彦写的一首小令。写的是夏天雨后清晨的景色，词人从屋里点香消暑写到屋外鸟雀欢唱，再写到池塘里雨后的荷花，一步步带我们走进清新明朗的早晨。最妙的是“一一风荷举”这句，荷叶被风轻轻托起的样子，像一个个小圆盘被举高，活泼可爱，让人觉得满池塘的荷花都在跳舞。这首词语言干净、画面优美，是宋词里写荷花最经典的句子之一，后来很多人画荷花、拍荷花，都会想起这句词呢。` }] },
  { id: 175, title: "牧童诗",
    author: "黄庭坚",
    dynasty: "宋",
    category: "宋",
    summary: "骑牛远远过前村，吹笛风斜隔岸闻，多少长安名利客，机关用尽不如君",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "牧童诗", original: "骑牛远远过前村，吹笛风斜隔岸闻，多少长安名利客，机关用尽不如君", translation: `同学们，我们来读一读这首《牧童诗》。第一句“骑牛远远过前村”，意思是：小牧童跨坐在牛背上，悠悠闲闲地走过前面的村庄。第二句“吹笛风斜隔岸闻”，讲的是：一阵斜风轻轻吹过，他吹奏的笛声随着风儿飘散开来，隔着一条河岸，人们都能听得清清楚楚。这句写得好，一个“斜”字让画面动了起来，笛声好像也带着风的方向飘向我们。第三句“多少长安名利客”，长安是唐朝的京城，“名利客”指那些成天追逐功名和钱财的人，诗人用“多少”二字，透露出对这类人的感叹。最后一句“机关用尽不如君”，是说那些人在官场和生意场上用尽各种心机、算尽计谋，到头来反而比不上这位自在逍遥的牧童。这首诗借赞颂牧童的悠闲，讽刺了追名逐利之徒，告诉我们：真正的快乐，未必藏在名利之中。`, interpretation: `这首诗出自宋代大诗人黄庭坚之手，写的是乡村牧童悠闲自在的生活。第一、二句描绘出一幅美丽的田园画面：牧童骑牛吹笛，声音随风飘过河岸，多么轻松愉快！三四句笔锋一转，把乡村的牧童和长安城里争名夺利的人做了对比。那些当官的、做生意的人整天算计来算计去，反而活得不如一个放牛的孩子开心。这首诗告诉我们：真正的快乐不一定来自金钱和地位，简单自由的生活也很美好。` }] },
  { id: 176, title: "寄黄几复",
    author: "黄庭坚",
    dynasty: "宋",
    category: "宋",
    summary: "桃李春风一杯酒，江湖夜雨十年灯",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "寄黄几复", original: "我居北海君南海，寄雁传书谢不能，桃李春风一杯酒，江湖夜雨十年灯", translation: `同学们，我们来读一读黄庭坚的《寄黄几复》。这首诗是诗人写给远方好友黄几复的一封信，表达了对朋友的深深思念。我住在北海边的山东，你住在遥远的南海边。想托大雁捎封信给你，可大雁也摇头说办不到——这里有个典故，说大雁南飞最远只到衡阳，南方太远它去不了。回想从前，桃李花开、春风拂面，我们一起举杯畅饮，那段友情多么美好。可如今各奔东西，整整十年了，我只能在江湖的夜雨中独对孤灯，默默思念着你。这句写得好，“江湖夜雨十年灯”，七个字里有孤独、有风雨、有漫长的岁月，藏着说不完的牵挂。`, interpretation: `这是北宋大诗人黄庭坚写给好友黄几复的一首名诗，当时黄庭坚被贬到山东德州，黄几复在遥远的广东，四年没有见面，思念之情就化作这首诗。这首诗最厉害的就是中间两句——'桃李春风一杯酒，江湖夜雨十年灯'，一共十四个字，却把少年相聚的快乐和成年分离的孤独全说尽了。'桃李春风'多暖啊，'江湖夜雨'多冷啊，'一杯酒'多短啊，'十年灯'多长啊！这种用画面说心情的写法，后来成了千古名句，连大文豪鲁迅都忍不住模仿呢。` }] },
  { id: 177, title: "满江红（节选）",
    author: "岳飞",
    dynasty: "宋",
    category: "宋",
    summary: "怒发冲冠，凭栏处，潇潇雨歇，抬望眼，仰天长啸，壮怀激烈，三十功名尘与土，八千里路云和月，莫等闲，白了少年头，空悲切",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "满江红（节选）", original: "怒发冲冠，凭栏处，潇潇雨歇，抬望眼，仰天长啸，壮怀激烈，三十功名尘与土，八千里路云和月，莫等闲，白了少年头，空悲切，靖康耻犹，未雪臣，子恨何时，灭驾长，车踏破贺，兰山缺壮，志饥餐胡虏肉笑，谈渴饮匈奴血待，从头收，拾旧山河朝，天阙", translation: `我愤怒得头发竖起来，几乎要冲掉帽子。独自靠着栏杆，潇潇的雨刚刚停下。抬头放眼远望，对着天空大声呼喊，胸怀多么激荡！三十年来虽然有了一点功名，却像尘土一样微不足道；转战八千里路，只有云和月作伴。不要白白浪费时光，不然等头发白了再后悔，也只能白白悲伤！靖康年的国耻还没有洗雪，我心中的仇恨什么时候才能消除？我要驾着战车，踏破贺兰山缺。满怀壮志，饿了就吃敌人的肉，笑着说话，渴了就喝匈奴的血。等着我重新收复失去的江山，再去朝见皇上吧！`, interpretation: `这首词写在南宋时期，当时金兵入侵，岳飞带领岳家军抗金，立志收复被金人占领的北方领土。词中最震撼的是‘怒发冲冠’四个字，把满腔怒火写得活灵活现。‘三十功名尘与土，八千里路云和月’特别出名，把为国打仗看得比功名利禄重要得多。‘壮志饥餐胡虏肉，笑谈渴饮匈奴血’虽然有点夸张，但读起来特别提气！后来这句‘莫等闲，白了少年头，空悲切’成了千古名句，鼓励了无数人珍惜时光、努力奋斗。岳飞虽然被害死了，但这首词一直激励着中国人爱国报国。` }] },
  { id: 178, title: "天净沙·秋思",
    author: "马致远",
    dynasty: "元",
    category: "元",
    summary: "枯藤老树昏鸦，小桥流水人家，古道西风瘦马，夕阳西下，断肠人在天涯",
    tags: "元,经典",
    color: "#ec4899",
    sections:[    { id: 1, title: "天净沙·秋思", original: "枯藤老树昏鸦，小桥流水人家，古道西风瘦马，夕阳西下，断肠人在天涯", translation: `同学们，我们来读一读这首元曲。枯萎的藤蔓紧紧缠绕着苍老的树枝，树枝上栖息着几只黄昏归巢的乌鸦。远处，一座小小的木桥横跨在潺潺的溪水之上，溪水边住着几户安宁的人家。词句里连用九个景物，句句都在写秋天萧瑟（xiāo sè，凄凉冷清）的景象，却没有一个“秋”字，这就是它写得好、写得妙的地方。紧接着，古老的驿道上刮起了阵阵西风，一匹骨瘦如柴的马驮着游子缓缓前行。太阳正慢慢地向西方落下，天色越来越暗，而这位满心愁苦、思念家乡的游子，依然孤零零地漂泊在遥远的天涯。这首小令的“曲眼”（全篇最传神的一个字）就在末尾的“断肠”二字，它道尽了所有离乡背井之人心中的悲苦，让人久久难忘。`, interpretation: `这首小令写于元代，那时候很多读书人怀才不遇，四处漂泊。马致远用短短二十八字，画出了一幅深秋黄昏图。你看——枯藤、老树、昏鸦、古道、瘦马、夕阳，全是让人心里发凉的东西，偏偏中间插了一句'小桥流水人家'，那是别人温暖的家乡啊！这一对比，路上游子的孤独立刻涌出来。最后一句'断肠人在天涯'，是全中国游子心里最柔软的那根弦。几百年来，离家在外的人读到这儿，都会鼻子一酸。` }] },
  { id: 179, title: "山坡羊·潼关怀古",
    author: "张养浩",
    dynasty: "元",
    category: "元",
    summary: "峰峦如聚，波涛如怒，山河表里潼关路，望西都，意踌躇，伤心秦汉经行处，宫阙万间，都做了土，兴百姓苦，亡百姓苦",
    tags: "元,经典",
    color: "#ec4899",
    sections:[    { id: 1, title: "山坡羊·潼关怀古", original: "峰峦如聚，波涛如怒，山河表里潼关路，望西都，意踌躇，伤心秦汉经行处，宫阙万间都做了土，兴，百姓苦，亡，百姓苦", translation: `华山的山峰一座座聚拢在一起，黄河的波涛汹涌澎湃像在发怒。潼关地势险要，外有黄河，内有华山，形成一道天然防线。遥望长安故都，我心中犹豫感慨。路过秦汉故地，心里真难受——当年无数宫殿楼阁，如今都化作了一片尘土。一个朝代兴起，百姓受苦；一个朝代灭亡，百姓还是受苦。`, interpretation: `这首小令写于元代，朝廷重新起用张养浩去陕西赈灾，他路过潼关时写下。那时战乱刚过，百姓流离失所，他看到山河依旧雄伟，可宫殿早已成了废墟，心里特别难过。'峰峦如聚，波涛如怒'把山水写活了，好像山在拥挤、河在咆哮，特别有气势。最厉害的是最后两句：'兴，百姓苦；亡，百姓苦'——不管哪个朝代兴起还是灭亡，受苦的总是老百姓！这短短八个字说出了千年历史最心酸的道理，所以这句成了流传千古的名句，也让我们明白：读历史，不光要看帝王将代，更要看老百姓的日子。` }] },
  { id: 180, title: "天净沙·春",
    author: "白朴",
    dynasty: "元",
    category: "元",
    summary: "春山暖日和风，阑干楼阁帘栊，杨柳秋千院中，啼莺舞燕，小桥流水飞红",
    tags: "元,写景",
    color: "#ec4899",
    sections:[    { id: 1, title: "天净沙·春", original: "春山暖日和风，阑干楼阁帘栊，杨柳秋千院中，啼莺舞燕，小桥流水飞红", translation: `春天，山坡暖暖的，阳光温柔地照着，和风轻轻吹来。栏杆旁边是漂亮的楼阁，窗户上的帘子垂着。院子里，杨柳轻轻摇摆，秋千静静地立着。小黄莺在枝头唱歌，小燕子飞来飞去跳着舞。小桥下面，流水哗哗地流，水上漂着飘落的红色花瓣。`, interpretation: `这首小曲是元代大诗人白朴写的《天净沙》四首之一，写的是春天的小院子。元朝人特别爱用短短的句子画出一幅画，你看——暖日、和风、杨柳、啼莺、飞红，一个景接一个景，就像电影镜头一样慢慢推过来。最有意思的是，这么多景物堆在一起，却一点都不乱，反而让人觉得特别安静、特别舒服。后人读这首词，常会想起自己小时候家附近的小花园，满眼都是春天的颜色呢！` }] },
  { id: 181, title: "天净沙·夏",
    author: "白朴",
    dynasty: "元",
    category: "元",
    summary: "云收雨过波添，楼高水冷瓜甜，绿树阴垂画檐，纱厨藤簟，玉人罗扇轻缣",
    tags: "元,写景",
    color: "#ec4899",
    sections:[    { id: 1, title: "天净沙·夏", original: "云收雨过波添，楼高水冷瓜甜，绿树阴垂画檐，纱厨藤簟，玉人罗扇轻缣", translation: `同学们，我们来读一读这首小令——《天净沙·夏》。它的作者是元代大诗人白朴，他用短短几句词，就画出了一幅清凉又美丽的夏日图景，让我们一句一句来看。开头两句写的是雨后的景色：云朵慢慢收起来了，雨刚刚停歇，池塘里的水涨起来了，波纹一圈一圈地荡开，瞧，水面是不是更热闹了？这句写得好，短短几个字，就让人感觉到了雨后空气的清新。接着写楼阁高高地立在那里，清凉的水让人觉得舒服，甜甜的西瓜正是夏天最解渴的宝贝。然后抬头一看，大树的绿荫低低地垂下来，挡住了彩画的屋檐，屋子里自然就凉快了许多。最后一句最让人羡慕：躺在纱帐和藤席上，美人轻轻摇着罗扇，身上穿着薄薄的丝绸衣裳，凉风阵阵，多么惬意呀！整首小令虽然只有几十个字，却写出了夏日的悠闲和清凉，是元曲里的名篇。`, interpretation: `这首小令写于元代，那时候文人常借山水景色表达心境。白朴用六个画面拼出夏日的清凉世界：雨过天晴、楼高水冷、瓜甜荫凉、纱帐藤席、美人轻扇。每一句都藏着一份惬意，读来像喝了一碗冰镇酸梅汤。写法上延续了元曲小令“白描”的特色，不用华丽辞藻，只把最鲜亮的几样夏日景物摆在一起，画面感十足。结尾的“玉人罗扇轻缣”是点睛之笔，让人觉得整个夏天都温柔起来了。` }] },
  { id: 182, title: "天净沙·秋",
    author: "白朴",
    dynasty: "元",
    category: "元",
    summary: "孤村落日残霞，轻烟老树寒鸦，一点飞鸿影下，青山绿水，白草红叶黄花",
    tags: "元,写景",
    color: "#ec4899",
    sections:[    { id: 1, title: "天净沙·秋", original: "孤村落日残霞，轻烟老树寒鸦，一点飞鸿影下，青山绿水，白草红叶黄花", translation: `同学们，我们来读一读这首小令——《天净沙·秋》。它是元代著名戏曲家白朴的作品。整首曲子就像一幅美丽的秋日画卷，描绘了从黄昏到夜晚的乡村景色。现在，我们一句一句地来看看：开头“孤村落日残霞”，说的是夕阳慢慢西沉，一座孤零零的小村庄，被傍晚天边残留的晚霞轻轻笼罩着。这句写得好，一个“孤”字，便让人感到宁静而略带忧伤。接着“轻烟老树寒鸦”，写的是村子里升起几缕淡淡的炊烟，缠绕在老树枝头，几只怕冷的乌鸦静静地栖息在上面。下一句“一点飞鸿影下”，意思是天空中有一只大雁飞过，只留下一个小小的身影。最后“青山绿水，白草红叶黄花”，描绘的是远处的山一片青葱，河水清澈流淌；地上的草已经枯黄变白，枫叶火一样红，野菊花金灿灿地盛开着。这首小令虽然没有写一个“人”字，却处处透着秋天的气息和诗人的情思。`, interpretation: `这首小令是元代白朴写的，描画了一幅深秋傍晚的乡村风景画。那时候许多文人不喜欢当官，就跑到乡间去写写画画，觉得大自然特别美。整首曲就像用五颜六色的彩笔，一句一个画面：村庄、落日、老树、飞鸿、红叶、黄花……读起来像看电影一样，一幅幅图从眼前滑过。妙在没有一个“秋”字，却处处都是秋天——寒鸦、黄花、白草都悄悄告诉你：叶子要落了，天要冷了。这就是白朴的厉害之处，用最少的字，画最浓的秋意，让人读了三百年还觉得美。` }] },
  { id: 183, title: "天净沙·冬",
    author: "白朴",
    dynasty: "元",
    category: "元",
    summary: "一声画角谯门，半庭新月黄昏，雪里山前水滨，竹篱茅舍，淡烟衰草孤村",
    tags: "元,写景",
    color: "#ec4899",
    sections:[    { id: 1, title: "天净沙·冬", original: "一声画角谯门，半庭新月黄昏，雪里山前水滨，竹篱茅舍，淡烟衰草孤村", translation: `城楼上的号角刚刚响了一声，天色就渐渐暗了下来，太阳也快要落山了。这时，半个院子里升起了弯弯的月亮，洒下淡淡的清光。这句写得好，用“一”和“半”这两个字，告诉我们冬天的傍晚来得又快又安静。接着看，雪花纷纷扬扬地飘落下来，落在了山前的小河边上，把小河也染上了一层洁白。同学们想一想，这是多美的画面呀！远处，有一间小房子，围着用竹子编成的篱笆，房顶冒着淡淡的炊烟。这是一个孤零零的小村子，到了冬天，村外到处长满了枯黄的野草，越发显得冷清和安静。`, interpretation: `这首小曲出自元代，是白朴写冬天的小令。那时候战争不断，很多村庄都变得冷清荒凉。整首曲子没有一个“冬”字，却处处是冬天的样子：号角声让人心里发紧，黄昏新月又冷又静，皑皑白雪配上孤零零的竹篱茅舍，再加上淡淡的炊烟和枯黄的野草，一幅孤寂的乡村冬景就出现在眼前啦。它最妙的地方是“淡烟衰草孤村”这六个字，简简单单，却让人感觉冷清又安静，读完好像能闻到田野里枯草的味道呢！` }] },
  { id: 184, title: "山坡羊·骊山怀古",
    author: "张养浩",
    dynasty: "元",
    category: "元",
    summary: "骊山四顾阿房一，炬当时奢侈今何，处只见草萧疏水，萦纡至今遗恨迷，烟树列国周齐秦，汉楚赢都变做了，土输都变做了土",
    tags: "元,怀古",
    color: "#ec4899",
    sections:[    { id: 1, title: "山坡羊·骊山怀古", original: "骊山四顾阿房一，炬当时奢侈今何，处只见草萧疏水，萦纡列国周齐秦，汉楚赢都变做了，土输都变做了土", translation: `在骊山四处眺望，阿房宫曾经就在那里。当年项羽一把大火，烧掉了秦朝所有的奢华。可如今那些宫殿楼阁都到哪里去了？只剩下荒草稀疏，流水弯弯绕绕。当年周、齐、秦、汉、楚等国家，不管是赢来的还是输掉的，最后全都变成了土。`, interpretation: `这首小令写于元朝，那时候很多文人看透了朝代更替，心里又难过又无奈。张养浩登上骊山，想起两千多年前秦始皇修建的巨大宫殿阿房宫，被项羽一把火烧成灰烬。他用“草萧疏”“水萦纡”这样安静冷清的景象，反衬当年秦朝的极度奢华，最后感叹：不管是赢是输，周、齐、秦、汉、楚，全都变成了土。这首曲子最大的特点就是对比强烈——繁华对荒草，胜利对失败，让人一眼就明白什么叫“兴亡”。它告诉我们：再大的权势、再美的宫殿，也挡不住时间的脚步。这种怀古的情怀，后来成了中国文学里一个特别重要的主题。` }] },
  { id: 185, title: "蟾宫曲·春情",
    author: "徐再思",
    dynasty: "元",
    category: "元",
    summary: "平生不会相思才，会相思便害相思，身似浮云心如飞，絮气若游丝空一，缕余香在此盼千，金游子何之证候，来时正是何时灯，半昏时月半明时",
    tags: "元,爱情",
    color: "#ec4899",
    sections:[    { id: 1, title: "蟾宫曲·春情", original: "平生不会相思才，会相思便害相思，身似浮云心如飞，絮气若游丝空一，缕余香在此盼千，金游子何之证候，来时正是何时灯，半昏时月半明时", translation: `我这一辈子啊，从来不懂什么是相思；可一旦懂了相思，就被相思给害苦了。我的身子像天上的浮云飘飘荡荡，心里像纷飞的柳絮乱糟糟的；我这一口气，就像一缕细细的游丝。我只剩下一点点残留的香气还在这里，苦苦等候那远行的情郎；你说，他到底去哪儿了？你快告诉我，他什么时候才回来呀？等到那灯光半明半暗、月亮半圆半亮的时候——就是现在，就是现在啊！`, interpretation: `这是元代小令家徐再思写的一首少女怀春的小曲，写得俏皮又动人。元代读书人仕途不顺，常常用爱情小曲来寄托心里的苦闷，这首曲子正是借少女的痴情，说出自己魂牵梦萦的滋味。整首曲子最大的妙处是全用少女的口吻，一句一个叹气，像在跟人撒娇诉苦；而最绝的是结尾，把少女的等待比作“灯半昏时月半明时”，那种又亮又暗、半梦半醒的朦胧感，把相思的滋味写得又美又心酸。后来“身似浮云，心如飞絮”还常被人们借用，来形容心里乱糟糟、坐立不安的样子呢。` }] },
  { id: 186, title: "卖花声·怀古",
    author: "张可久",
    dynasty: "元",
    category: "元",
    summary: "美人自刎乌，江边战火，曾烧赤壁山将军，空老玉门关伤心，秦汉生民，涂炭读书人，一声长叹",
    tags: "元,怀古",
    color: "#ec4899",
    sections:[    { id: 1, title: "卖花声·怀古", original: "美人自刎乌，江边战火，曾烧赤壁山将军，空老玉门关伤心，秦汉生民，涂炭读书人，一声长叹", translation: `同学们，我们来读一读这首《卖花声·怀古》。第一句“美人自刎乌江边”，讲的是当年项羽兵败，宠爱的虞姬在乌江边拔剑自刎。第二句“战火曾烧赤壁山”，说的是三国时期孙权与刘备联手，在赤壁山用火攻大败曹操，熊熊烈火烧红了整座山。第三句“将军空老玉门关”，是说那些英勇的将军们，戍守边关直到白头，却没能建功立业，真是白白老去。这句写得好，一个“空”字道尽了壮志难酬的悲哀。第四句“伤心秦汉生民涂炭”，是说秦汉年间战乱不断，老百姓生活困苦，如同陷入泥沼与炭火之中。最后一句“读书人一声长叹”，表达了读书人面对历史兴亡，只能发出无奈的感叹。整首词借古讽今，提醒我们珍惜太平生活。`, interpretation: `这首小令是元代张可久怀古伤时之作。背景是元朝，读书人地位低下，科举时断时续，知识分子报国无门。作者一口气连用虞姬自刎垓下、赤壁烽火、班超老死边关三个典故，核心意象是"空"与"伤心"——英雄末路、壮志难酬。艺术上，它把历史故事压缩在短短几句中，像放电影一样快速切换场景，最后落在读书人的一声长叹上，特别打动人心。这首曲让千百年后的我们也能感受到：当天下大乱时，最先受苦的是百姓，最无奈的便是读书人啊！` }] },
  { id: 187, title: "水仙子·夜雨",
    author: "徐再思",
    dynasty: "元",
    category: "元",
    summary: "一声梧叶，一声秋一，点芭蕉一，点愁三更，归梦三更，后落灯花，棋未收叹，新丰孤馆，人留枕上，十年事江，南二老忧，都到心头",
    tags: "元,感怀",
    color: "#ec4899",
    sections:[    { id: 1, title: "水仙子·夜雨", original: "一声梧叶，一声秋一，点芭蕉一，点愁三更，归梦三更，后落灯花，棋未收叹，新丰孤馆，人留枕上，十年事江，南二老忧，都到心头", translation: `一片梧桐叶落，发出轻轻一声响，让人觉得秋天来了。一点雨打在芭蕉叶上，也像是一点愁绪落在心头。三更半夜，好不容易做个回家的梦，却被灯光跳动惊醒了。下棋下到一半没收起来，叹气我这孤独的旅店啊。想睡也睡不着，躺在枕上回想过去十年的事，江南家乡年迈的父母，他们的担忧牵挂，全都涌到了我的心头。`, interpretation: `这首小令写于元代，当时许多读书人为求功名背井离乡，徐再思也是其中之一。秋天夜雨本是平常景象，可对独自住在旅店的人来说，每一声雨都像敲在心上。梧桐、芭蕉是古典诗词里代表愁苦的“老朋友”了，雨滴落在上面，一声声就像把愁也一点点滴进心里。三更归梦被灯火惊破，想家的情绪再也压不住，十年漂泊的辛酸、远方父母的担忧，一下子全涌上来。整首曲子像一场秋雨，从头到尾层层加码，越听越觉得心里湿漉漉的。这种把细微声响和内心愁苦叠在一起写的手法，就是元曲最动人的地方。` }] },
  { id: 188, title: "画鸡",
    author: "唐寅",
    dynasty: "明",
    category: "明",
    summary: "头上红冠不用戴，满身雪白走将来，平生不敢轻言语，一叫千门万户开",
    tags: "明,经典",
    color: "#ef4444",
    sections:[    { id: 1, title: "画鸡", original: "头上红冠不用戴，满身雪白走将来，平生不敢轻言语，一叫千门万户开", translation: `同学们，这首《画鸡》是明代大才子唐寅写的，他特别擅长画画，也爱写诗。今天我们来读一读这首有趣的小诗吧！第一句说，大公鸡头上本来就长着红红的冠子，像戴着一顶漂亮的红帽子，根本不用另外去戴。第二句写的是，它浑身的羽毛洁白如雪，走起路来雄赳赳、气昂昂，多神气呀！第三句说，它平时安安静静的，从来不敢随便乱叫唤。最后一句最精彩，它说只要公鸡喔喔喔地一打鸣，千家万户的人们就会打开门，开始新一天的忙碌生活。这句写得好极了，让人一下子就能感受到清晨热闹又温馨的画面。读完了这首诗，我们懂得了大公鸡虽然外表美丽、性格沉稳，可它一声啼叫，就能唤醒整个世界，真是一位了不起的清晨小使者呢！`, interpretation: `这首诗是明代才子唐伯虎写的，他不仅会画画，写诗也特别有趣！诗里说的是一只漂亮的大白公鸡：头顶红冠、身穿白袍，威风又漂亮。古人把鸡叫当成天亮的信号，所以"一叫千门万户开"成了千古名句，意思是一只鸡一叫，整个世界都醒过来啦！唐寅用大白话写诗，就像在跟小朋友聊天一样，读起来又顺口又好玩，这种活泼的风格后来很多人都在学呢。` }] },
  { id: 189, title: "临江仙·滚滚长江东逝水（节选）",
    author: "杨慎",
    dynasty: "明",
    category: "明",
    summary: "滚滚长江东逝水，浪花淘尽英雄，是非成败转头空，青山依旧在，几度夕阳红",
    tags: "明,经典",
    color: "#ef4444",
    sections:[    { id: 1, title: "临江仙·滚滚长江东逝水（节选）", original: "滚滚长江东逝水，浪花淘尽英雄，是非成败转头空，青山依旧在，几度夕阳红，白发渔樵江渚上，惯看秋月春风，一壶浊酒喜相逢，古今多少事，都付笑谈中", translation: `汹涌奔腾的长江向东流去，一去不回头。浪花把英雄人物都冲洗得无影无踪。成功失败、对错是非，转眼之间都成了空。青山还是老样子，夕阳却红了又落，落了又红。江边小洲上，白头发的渔夫和砍柴人，早已看惯了秋天的月亮和春天的风。难得碰上老朋友，一壶粗酒就够开心啦。从古到今多少事情，全都在笑谈中说一说罢了。`, interpretation: `这首词是明代才子杨慎的千古绝唱，写于他被朝廷流放云南的路上。那时他心里特别苦闷，回头想想人生：再厉害的英雄，也会被时间冲走；再大的事儿，过几年也成了闲聊的笑话。你看词里写了滚滚长江、青山夕阳、秋月春风，还有白发渔夫笑谈古今，多么洒脱！这种把大悲大愁变成云淡风轻的写法，特别厉害。后来它随着《三国演义》传遍全国，连老爷爷都能哼上两句“滚滚长江东逝水”呢！` }] },
  { id: 190, title: "幼女词",
    author: "毛铉",
    dynasty: "明",
    category: "明",
    summary: "下床着新衣，初学小姑拜，低头羞见人，双手结裙带",
    tags: "明,写景",
    color: "#ef4444",
    sections:[    { id: 1, title: "幼女词", original: "下床着新衣，初学小姑拜，低头羞见人，双手结裙带", translation: `同学们，今天我们来读一首特别有意思的小诗，叫做《幼女词》。这首诗写的是一个小女孩第一次学着大人行礼的情景，生动极了。我们来一句一句地读：

下床着新衣：早上一起床，小姑娘就高高兴兴地穿上了新做的衣裳。

初学小姑拜：这是什么意思呢？"小姑"指的是新娘子，"拜"就是古代行礼问好的动作。小姑娘是头一回学着新娘的样子行礼，所以她心里又好奇又紧张。

低头羞见人：因为害羞呀，她把头低低地垂下来，不好意思抬头看人，小脸蛋儿一定红扑扑的。

双手结裙带：两只小手紧紧地抓着裙子的腰带，不知道该怎么放才好。

这句写得好！诗人只用短短四句，就把小女孩天真害羞的样子写得活灵活现，让咱们读了都忍不住想笑呢。`, interpretation: `这首小诗来自明代毛铉的手笔，就像一幅生动可爱的小画。诗中描写的是一位即将出嫁的小姑娘，天没亮就起床，换上新嫁衣，学着已经出嫁的姐姐（古诗里叫"小姑"）的样子向长辈行礼。小姑娘又紧张又害羞，低着头不敢看人，只好紧紧攥着裙带——这一抓，把小女孩的忐忑和天真全写活了。诗人没有用华丽的词藻，只用"下床、着衣、学拜、低头、结带"这些朴素的动词，就把一个小女孩的可爱模样刻在了纸上，读来让人忍不住会心一笑。后来"双手结裙带"成了形容少女娇羞的经典名句，被很多人喜爱和传诵。` }] },
  { id: 191, title: "马上作",
    author: "戚继光",
    dynasty: "明",
    category: "明",
    summary: "南北驱驰报主情，江花边草笑平生，一年三百六十日，多是横戈马上行",
    tags: "明,边塞",
    color: "#ef4444",
    sections:[    { id: 1, title: "马上作", original: "南北驱驰报主情，江花边草笑平生，一年三百六十日，多是横戈马上行", translation: `同学们，我们来读一读戚继光的《马上作》。这首诗写的是一位将军骑着马到处打仗的生活。

第一句"南北驱驰报主情"，意思是说我骑着马在南方和北方到处奔走，是为了报答君主的信任和恩情。

第二句"江花边草笑平生"，说的是路边的江花和边塞的野草，好像在笑我这一辈子总是在路上奔波。

第三句和第四句"一年三百六十日，多是横戈马上行"是说，一年到头三百六十天里，大多数日子我都是横握着长戈、骑马在战场上度过的。

这句写得好！一个"横戈"的将军形象跃然纸上，让我们看到了一位保家卫国、日夜征战的大英雄。`, interpretation: `这首诗写于明代，当时倭寇侵扰东南沿海，北方又有鞑靼威胁，戚继光一生南征北战，是著名的抗倭英雄。这首诗是他戎马生涯的真实写照。诗中没有豪言壮语，只用朴实的语言写出将军的日常：常年在外，跨马持戈，江花与边草是他最熟悉的风景。其中'一年三百六十日，多是横戈马上行'广为传诵，成为描写军旅生涯的名句，也让我们看到一位英雄将军背后日复一日的辛劳与忠诚。` }] },
  { id: 192, title: "论诗",
    author: "李贽",
    dynasty: "明",
    category: "明",
    summary: "天生龙湖，以待卓吾，天生卓吾，乃在龙湖",
    tags: "明,经典",
    color: "#ef4444",
    sections:[    { id: 1, title: "论诗", original: "天生龙湖，以待卓吾，天生卓吾，乃在龙湖", translation: `老天爷创造出这片又清又美的龙湖，就像专门为一个人准备好了家园。原来啊，它是在等一个人——这位叫李卓吾的先生。上天把他带到这个世界上，就是让他住到龙湖这里来。你看，湖水静静地等着，人也刚刚好来到这里，湖水和人像是天生的一对朋友，谁也离不开谁。`, interpretation: `这首诗出自明代大思想家李贽之手。李贽号“龙湖老人”，晚年隐居在湖北麻城龙湖芝佛院，所以自称“卓吾”。短短四句，用“天生……以……”的反复手法，把龙湖和李贽说成是天造地设的一对，读起来像是一首小孩子的绕口令，特别有趣！别看它短，李贽可是明代最敢说实话的哲学家，他反对假道学，主张童心说，这首小诗里也透着他自信洒脱的劲儿：天地特意为我准备了这片湖，我也恰好属于这里。` }] },
  { id: 193, title: "春暮",
    author: "谢榛",
    dynasty: "明",
    category: "明",
    summary: "春色已过半，山花犹未开，石泉流旧影，林鸟送新哀",
    tags: "明,写景",
    color: "#ef4444",
    sections:[    { id: 1, title: "春暮", original: "春色已过半，山花犹未开，石泉流旧影，林鸟送新哀", translation: `同学们，我们来读一读这首小诗——《春暮》。题目里的“暮”，不是傍晚的意思，而是“晚、快要结束”的意思。所以“春暮”就是说：春天快要过去了。

第一句“春色已过半”，意思是春天美丽的景色，已经过去一大半了。一个“已”字，写出了诗人心中淡淡的失落。

第二句“山花犹未开”，“犹”是“还”的意思，说的是山上的野花还没来得及开放呢。这句写得好！花儿错过了春天，多让人可惜呀。

第三句“石泉流旧影”，讲的是山间石缝里的泉水，依然照旧静静地流淌着，水面上还映着熟悉的倒影。一个“旧”字，仿佛在说：风景还是去年的风景，可看风景的心情已经不同了。

第四句“林鸟送新哀”，是说树林里的鸟儿叽叽喳喳地叫着，那声音听起来像是在替春天唱一首告别的哀歌。“新哀”二字特别动人——旧花未开，新愁又添，正是春暮最让人惆怅的地方。`, interpretation: `这首小诗出自明代诗人谢榛之手。谢榛是明代诗坛"后七子"之一，特别擅长写山水田园诗。这首诗写的是暮春时节，山中景色。诗人发现春天都快结束了，山花却还没开，这让他觉得有点遗憾。泉水还是老样子静静流淌，可林中的鸟叫声听起来却像是在伤心地告别春天。整首诗短短二十字，却写出了春末山中又安静又有点忧伤的感觉，特别有画面感。其中"林鸟送新哀"一句最妙，明明是鸟在叫，诗人却听出了"哀伤"的味道，这就是古人说的"一切景语皆情语"啦！` }] },
  { id: 194, title: "出塞",
    author: "戚继光",
    dynasty: "明",
    category: "明",
    summary: "郁葱千里绿阴肥，涧水萦纡一径微，鱼为惊钩闻鼓动，鸟因避帜傍人飞",
    tags: "明,边塞",
    color: "#ef4444",
    sections:[    { id: 1, title: "出塞", original: "郁葱千里绿阴肥，涧水萦纡一径微，鱼为惊钩闻鼓动，鸟因避帜傍人飞", translation: `同学们，我们来读一读这首诗。放眼望去，郁郁葱葱的树木连绵千里的绿荫，草木长得又浓密又茂盛，这是一幅多么生机勃勃的边塞景象啊！山涧中的溪水弯弯曲曲地向前流淌，沿着水流望去，只能看到一条又细又窄的小路，悄悄伸向远方。忽然之间，鼓声咚咚响起，水中的鱼儿因为听到鼓声受了惊，纷纷游动起来；旁边的鸟儿也因为害怕高高的军旗，只好贴着人的身边匆匆飞过。这句写得好！一个“傍人飞”，把鸟儿惊慌躲避的样子写得活灵活现，让我们仿佛身临其境，看到了军营旁既热闹又有些紧张的场面。`, interpretation: `这首诗出自明代抗倭名将戚继光之手。他不仅是威震敌胆的军事家，也是一位才华横溢的诗人。明朝时，东南沿海常受倭寇侵扰，戚继光率军守卫边疆，写下许多边塞诗。诗中描绘了一幅生机勃勃的军营边景：千里绿荫、溪水弯弯，写出了边地的清幽与美丽。但有趣的是，连鱼儿听见鼓声就惊跳，鸟儿也因为旗帜而绕道而飞，从侧面生动地写出了军纪严明、戒备森严的气氛。这种"以乐景写警觉"的手法，让风景里藏着将士们的警惕，是这首诗最妙的地方。` }] },
  { id: 195, title: "郑板桥题画诗",
    author: "郑燮",
    dynasty: "清",
    category: "清",
    summary: "衙斋卧听萧萧竹，疑是民间疾苦声，些小吾曹州县吏，一枝一叶总关情",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "郑板桥题画诗", original: "衙斋卧听萧萧竹，疑是民间疾苦声，些小吾曹州县吏，一枝一叶总关情", translation: `同学们，我们来读一读清代画家郑板桥写的一首题画诗。诗人躺在县衙的书房里休息，忽然听见窗外一阵阵风吹竹叶的沙沙声。他心里一动，不由地想：这竹子发出的声音，多么像是老百姓生活艰难、日子困苦的哀叹啊！虽然我们这些小小的州县小官，职位并不显赫，但是百姓的事情哪怕再细小、再琐碎，也都值得我们用心去牵挂。这句写得好——“一枝一叶总关情”，把竹子的枝叶比作百姓的疾苦，说明好官应当把老百姓的冷暖放在心上。`, interpretation: `这首诗是郑板桥在山东潍坊做县官时画了一幅风竹图，然后题在画上的诗。当时他关心百姓疾苦，看到竹子在风中摇晃，就联想到老百姓的困苦生活。诗中最妙的是把风吹竹叶的沙沙声比作百姓的叹息，想象力非常奇特。整首诗语言朴实，却表达了一位小官对老百姓深深的牵挂。名句"一枝一叶总关情"流传很广，意思是哪怕是一件小事，也都牵动着我们的心，现在常用来形容对群众细致入微的关怀。` }] },
  { id: 196, title: "潍县署中画竹呈年伯包大中丞括",
    author: "郑燮",
    dynasty: "清",
    category: "清",
    summary: "衙斋卧听萧萧竹，疑是民间疾苦声，些小吾曹州县吏，一枝一叶总关情",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "潍县署中画竹呈年伯包大中丞括", original: "小時不識月，呼作白玉盤。又疑瑤臺鏡，飛在白雲端。仙人垂兩足，桂樹作團團。白兔擣藥成，問言與誰餐。蟾蜍蝕圓影，大明夜已殘。羿昔落九烏，天人清且安。陰精此淪惑，去去不足觀。憂來其如何，悽愴摧心肝。", translation: `小时候我不认识月亮，把它叫做白色的玉盘。又怀疑是神仙宫里的宝镜，飞到了白云的上面。月里的仙人刚垂下两只脚，桂花树还是团团圆圆的小芽。白兔捣的仙药已经成了，问一声：这是给谁吃的呀？蟾蜍把圆月啃出了缺口，明亮的月亮到了深夜已经残缺。羿从前射下九个太阳，天上人间都清静平安。这月亮被阴精沦惑侵蚀，远远离去不再值得观看。忧伤来了又能怎样呢，凄凉悲伤得让人心肝欲碎。`, interpretation: `这首诗是李白借儿童的眼睛看月亮的天真想象，再写月亮被蟾蜍吞食、渐渐残缺的忧惧，最后寄托对人生苦闷的感慨。诗人用白玉盘、瑶台镜、桂树、白兔、蟾蜍等神话意象，把月亮写得有情有味。语言清新如童话（'小时不识月'流传千古），后段陡然转悲，从童趣跌入忧愤，正是李白诗'清水出芙蓉，天然去雕饰'的典范——想象瑰丽、情感真挚，被后人反复吟咏。` }] },
  { id: 197, title: "论诗",
    author: "赵翼",
    dynasty: "清",
    category: "清",
    summary: "李杜诗篇万口传，至今已觉不新鲜，江山代有才人出，各领风骚数百年",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "论诗", original: "李杜诗篇万口传，至今已觉不新鲜，江山代有才人出，各领风骚数百年", translation: `同学们，我们来读一读清代诗人赵翼写的《论诗》。诗人告诉我们：李白和杜甫的诗篇非常厉害，从古至今有无数人传诵赞美，他们的名气大得很呢！可是到了今天，再去读那些诗，已经让人感觉不再那么新鲜了。接着诗人笔锋一转，赞美地说：祖国的大好河山啊，一代接着一代，总会有才华横溢的人才涌现出来，他们各自在文坛上大显身手，引领风骚长达好几百年。这句写得好！它告诉我们一个道理：每个时代都有自己了不起的诗人，不必只崇拜古人，长大后的你们说不定也能写出好诗呢。`, interpretation: `这是清代诗人赵翼写的一首谈诗论艺的小诗，充满了对文学发展的远见卓识。赵翼生活在清代，当时很多人盲目崇拜古人，把李白、杜甫的诗奉为不可超越的经典。而赵翼却大胆地说：李杜的诗虽好，但时代在变，今天读来已不再新鲜。这句“江山代有才人出，各领风骚数百年”，成了千古名句，鼓励了一代又一代的年轻人勇于创新、敢于超越前人。它告诉我们：每个时代都有自己的人才，不必迷信古人，自信地写出属于自己时代的好作品吧！` }] },
  { id: 198, title: "木兰花令",
    author: "纳兰性德",
    dynasty: "清",
    category: "清",
    summary: "人生若只如初见，何事秋风悲画扇，等闲变却故人心，却道故人心易变",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "木兰花令", original: "人生若只如初见，何事秋风悲画扇，等闲变却故人心，却道故人心易变，骊山语罢清宵半，泪雨霖铃终不怨，何如薄幸锦衣郎，比翼连枝当日愿", translation: `如果人生永远像第一次见面那样该多好啊。秋风吹冷了画上的扇子，相爱的人也变了心。平平常常就改变了从前的情意，却反过来说对方的心思容易变。还记得骊山夜半私语的时候，虽然像雨一样流了很多泪，但始终不抱怨。哪里比得上那薄情的富贵公子呢？只愿像鸟儿一样比翼双飞、枝干相连，那可是当初说好的心愿啊。`, interpretation: `这首词是清代大词人纳兰性德写的，他出身贵族，却写出了许多深情动人的词句。词中借用汉代班婕妤被冷落、秋扇被收起的典故，感叹人心易变；又用唐明皇与杨贵妃骊山相守的旧事，回忆当初的甜蜜。整首词最打动人的是开头那句'人生若只如初见'，意思是如果一切都停留在最初相遇的那一刻该多好，多么让人心酸的愿望啊！后来很多人写情书、说心里话，都会用上这句话，已经成了中国文学里最著名的'意难平'金句之一。` }] },
  { id: 199, title: "十二月十五夜",
    author: "袁枚",
    dynasty: "清",
    category: "清",
    summary: "沉沉更鼓急，渐渐人声绝，吹灯窗更明，月照一天雪",
    tags: "清,写景",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "十二月十五夜", original: "沉沉更鼓急，渐渐人声绝，吹灯窗更明，月照一天雪", translation: `同学们，今天我们来读一首清代诗人袁枚写的小诗《十二月十五夜》。题目告诉我们，这是农历十二月十五日的夜晚，也就是快要过年的一个冬夜。让我们一句一句地来读：第一句“沉沉更鼓急”，意思是打更的鼓声又沉又重，一声紧接一声地响着。更鼓是古代用来报时的鼓，每隔一段时间就要敲一次，告诉人们现在是什么时辰。第二句“渐渐人声绝”，是说随着夜越来越深，街上人们的说话声、吵闹声也慢慢消失了，四周变得安静下来。第三句“吹灯窗更明”，讲的是诗人吹灭了桌上的油灯，可是窗户却显得比点灯时还要明亮。为什么呢？这就要看第四句了——“月照一天雪”，原来是窗外下了一场大雪，月光洒在洁白的雪地上，反射出明亮的光，把天地都映得一片通明。这句写得好极了，一个“一天雪”，让我们仿佛看到到处都是白茫茫的雪景，又明亮又安静。整首诗虽然只有二十个字，却描绘出一个又寒冷、又寂静、又明亮的冬夜景象，让人读后久久难忘。`, interpretation: `这首诗写于清代，袁枚是当时著名诗人，性格率真，喜欢写身边小事。这首诗没有写人，专门写声音和光影的变化：更鼓声越来越急，说明夜深了；人声没有了，说明街上安静了；吹灭灯后窗户反而更亮，这是一个很有趣的发现——原来不是窗户亮，是外面的雪地反射着月光，雪夜的光比屋里还强。袁枚用最简单的话，写出了雪夜最独特的感受，让人读了也想推开窗户看一看。这首诗也让我们知道：安静的时候，耳朵会更灵；黑暗的时候，眼睛会看得更清楚。` }] },
  { id: 200, title: "山雨",
    author: "何绍基",
    dynasty: "清",
    category: "清",
    summary: "短笠团团避树枝，初凉天气野行宜，溪云到处自相聚，山雨忽来人不知",
    tags: "清,写景",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "山雨", original: "短笠团团避树枝，初凉天气野行宜，溪云到处自相聚，山雨忽来人不知", translation: `同学们，我们来读一读这首小诗。诗中写的是一位山野间的旅人，戴着一顶圆圆的小斗笠，巧妙地避开路边伸出的树枝，悠然前行。天气刚刚开始转凉，秋意初现，这样的日子最适合到山野间走一走、看一看。溪边的云朵自顾自地聚在一起，一会儿聚拢，一会儿又散开，仿佛在悠闲地玩耍。忽然之间，山雨悄然而至，噼噼啪啪地落了下来，可走在路上的人却浑然不觉。这句写得好！一个“忽”字，把山雨来得快、来得急、来得悄无声息的特点全都写出来了，让人读了仿佛也感受到那份突如其来的清凉。整首诗短短四句，却描绘出了一幅清新又灵动的山间行旅图，告诉我们要留心观察身边的大自然，哪怕是一阵风、一朵云、一场雨，都藏着无穷的趣味。`, interpretation: `这首诗写于清代，当时诗人喜爱到大自然中寻找乐趣。诗中最有趣的地方是：明明下着雨，诗人却说不晓得——原来山雨细密轻柔，像云朵悄悄聚起来一样，等你发现时，衣裳可能已经微微湿了。'溪云自相聚'特别有画面感，云像一群贪玩的小伙伴，说聚就聚。这首诗告诉我们：山里的天气变化很快，下雨也不一定是坏事，有时还带着凉凉的美呢！短短四句，把山间漫步的悠闲写得活灵活现，是清代写景小诗中的佳作。` }] },
]
